class _MaintenanceUser:
    """Minimal Flask-Login compatible user returned when the DB is unreachable.
    Lets a previously-authenticated admin session pass @login_required so they
    can reach the database settings page to fix the connection."""
    is_authenticated = True
    is_active = True
    is_anonymous = False
    is_sub_admin = False

    def __init__(self, uid=0):
        self.id = uid

    def get_id(self):
        return str(self.id)

    def has_permission(self, _key):
        return True


@login_manager.user_loader
def load_user(user_id):
    if _DB_MAINTENANCE_MODE:
        try:
            return _MaintenanceUser(int(user_id))
        except (TypeError, ValueError):
            return None
    return db.session.get(User, int(user_id))


class PermissionGroup(db.Model):
    """A named set of permissions that can be shared across many sub-admin users.
    Editing the group instantly updates every member's effective permissions."""
    __tablename__ = 'permission_group'

    id = db.Column(db.Integer, primary_key=True)
    owner_user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=False)
    name = db.Column(db.String(100), nullable=False)
    description = db.Column(db.String(500), nullable=True)
    permissions = db.Column(db.JSON, nullable=True)
    website_permissions = db.Column(db.JSON, nullable=True, default=dict)
    # Per-external-drive access toggle. Keys are str(StorageConnection.id),
    # values bool. Missing key = allowed (backwards-compatible default).
    storage_connection_access = db.Column(db.JSON, nullable=True, default=dict)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)

    members = db.relationship(
        'User',
        foreign_keys='User.permission_group_id',
        backref=db.backref('permission_group', lazy='select'),
        lazy=True,
    )

    def to_dict(self):
        return {
            'id': self.id,
            'name': self.name,
            'description': self.description or '',
            'permissions': self.permissions or {},
            'website_permissions': self.website_permissions or {},
            'storage_connection_access': self.storage_connection_access or {},
            'member_count': len(self.members),
        }


# Holding any of the "implying" permissions on the right automatically grants
# the "implied" key on the left (e.g. anyone who can edit/email/2fa/backup the
# site settings can also reach the settings page to do so).
PERMISSION_IMPLIES = {
    'settings.view': ('settings.edit', 'settings.email', 'settings.2fa', 'settings.backup'),
}


class User(UserMixin, db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(150), unique=True, nullable=False)
    email = db.Column(db.String(150), unique=True, nullable=False)
    password_hash = db.Column(db.Text, nullable=False)
    # Optional real name — collected at signup, editable later. Used for
    # administration and (eventually) social surfaces. Never lowercased.
    first_name = db.Column(db.String(100), nullable=True)
    last_name  = db.Column(db.String(100), nullable=True)
    # Sub-admin support: if set, this user belongs to the parent admin
    parent_user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=True)
    permission_group_id = db.Column(db.Integer, db.ForeignKey('permission_group.id'), nullable=True)
    permissions = db.Column(db.JSON, nullable=True)  # dict of 'section.action': bool
    # A co-owner is a sub-admin elevated to full, unrestricted control (same as
    # the main admin) so the system isn't dependent on a single account. Their
    # data still belongs to the root (root_user_id is unchanged), so it's shared
    # full access, not a separate silo.
    is_co_owner = db.Column(db.Boolean, nullable=False, default=False,
                            server_default=_sa_false())

    two_factor_enabled = db.Column(db.Boolean, nullable=False, default=False)
    two_factor_email = db.Column(db.String(255), nullable=True)
    two_factor_activated_at = db.Column(db.DateTime, nullable=True)
    two_factor_last_email_settings_version = db.Column(db.String(64), nullable=True)
    two_factor_disabled_reason = db.Column(db.String(255), nullable=True)
    two_factor_disabled_at = db.Column(db.DateTime, nullable=True)
    two_factor_last_sent_at = db.Column(db.DateTime, nullable=True)
    last_login_at = db.Column(db.DateTime, nullable=True)
    last_seen_at  = db.Column(db.DateTime, nullable=True)
    two_factor_needs_attention = db.Column(
        db.Boolean,
        nullable=False,
        default=False,
        server_default=_sa_false()
    )
    admin_url_key = db.Column(db.String(120), nullable=True)
    admin_url_key_enabled = db.Column(db.Boolean, nullable=False, default=False)
    # Org-wide policy (only meaningful on the anchor / primary owner): when on,
    # EVERY admin must pass email 2FA at login, regardless of their personal
    # 2FA enrollment. Replaces the old implicit "the owner's own 2FA forces the
    # team" cascade with an explicit, transfer-proof setting.
    org_require_2fa = db.Column(db.Boolean, nullable=False, default=False,
                                server_default=_sa_false())
    # Email-settings fingerprint captured when the org policy was verified; if it
    # no longer matches, the policy auto-disables (mirrors per-user 2FA). The
    # needs-attention flag lets the UI explain why it switched off.
    org_2fa_email_settings_version = db.Column(db.String(64), nullable=True)
    org_2fa_needs_attention = db.Column(db.Boolean, nullable=False, default=False,
                                        server_default=_sa_false())
    # Phone for SMS notifications + optional SMS-based 2FA. Both off-by-default
    # so existing installs stay email-only unless the admin opts in.
    phone_number      = db.Column(db.String(40), nullable=True)
    sms_2fa_enabled   = db.Column(db.Boolean, nullable=False, default=False,
                                  server_default=_sa_false())

    timezone = db.Column(db.String(100), nullable=False, default='America/Chicago')
    date_format = db.Column(db.String(50), nullable=False, default='%b %d, %Y %I:%M %p')
    admin_navbar_disabled = db.Column(db.JSON, nullable=True, default=list)
    # Org-wide admin branding (lives on the anchor). NULL falls back to the
    # default "uwebia" name / icon. Shown on the admin navbar & admin login page.
    admin_brand_name = db.Column(db.String(80), nullable=True)
    admin_brand_icon_url = db.Column(db.String(500), nullable=True)
    admin_chat_last_read = db.Column(db.DateTime, nullable=True)
    website_permissions = db.Column(db.JSON, nullable=True, default=dict)
    # Per-external-drive access toggle. Keys are str(StorageConnection.id),
    # values bool. Missing key = allowed (backwards-compatible default).
    storage_connection_access = db.Column(db.JSON, nullable=True, default=dict)

    websites = db.relationship('Website', backref='owner', lazy=True, cascade="all, delete-orphan")
    _is_active = db.Column(db.Boolean, default=True)  # Use a different attribute name

    @validates('username')
    def normalize_username(self, key, value):
        return value.strip().lower()

    @validates('email')
    def normalize_email(self, key, value):
        return value.strip().lower()

    @validates('first_name', 'last_name')
    def normalize_name(self, key, value):
        v = (value or '').strip()
        return v or None

    @property
    def full_name(self):
        """First + last, omitting blanks; None when neither is set."""
        return ' '.join(p for p in (self.first_name, self.last_name) if p) or None

    def get_id(self):
        return str(self.id)

    @property
    def is_authenticated(self):
        return True  # Assuming all users are authenticated

    @property
    def is_active(self):
        return self._is_active  # Implement according to your logic

    @property
    def is_anonymous(self):
        return False  # Assuming all users are not anonymous

    def set_password(self, password):
        self.password_hash = generate_password_hash(password)

    def check_password(self, password):
        return check_password_hash(self.password_hash, password)

    @property
    def is_sub_admin(self):
        return self.parent_user_id is not None

    @property
    def root_user_id(self):
        """The owning admin's user ID (self for main admins, parent for sub-admins)."""
        return self.parent_user_id or self.id

    @property
    def is_full_admin(self):
        """Full, unrestricted control: the main admin OR a co-owner. Use this for
        permission gating. (is_sub_admin stays True for co-owners — their DATA is
        still the root's, so data-scoping that branches on is_sub_admin is right.)"""
        return (self.parent_user_id is None) or bool(self.is_co_owner)

    def _direct_permission(self, key, website_id=None):
        """Resolve a single permission key with no implication fallback:
        per-website override first, then group, then individual global."""
        # Per-website override takes precedence when a website context is given
        if website_id is not None:
            wp = (self.website_permissions or {}).get(str(website_id), {})
            if key in wp:
                return bool(wp[key])
        # Check group's website-specific override before group's global
        if self.permission_group_id and self.permission_group:
            if website_id is not None:
                grp_wp = (self.permission_group.website_permissions or {}).get(str(website_id), {})
                if key in grp_wp:
                    return bool(grp_wp[key])
            return bool((self.permission_group.permissions or {}).get(key, False))
        return bool((self.permissions or {}).get(key, False))

    def has_permission(self, key, website_id=None):
        """Full admins (main admin or co-owner) always have all permissions.
        Other sub-admins check per-website overrides first, then their group (if
        any), then individual global permissions. A key is also granted when the
        user holds any permission that implies it (see PERMISSION_IMPLIES)."""
        if self.is_full_admin:
            return True
        if self._direct_permission(key, website_id):
            return True
        for implying in PERMISSION_IMPLIES.get(key, ()):
            if self._direct_permission(implying, website_id):
                return True
        return False

    def __repr__(self):
        return f"<User {self.username}>"


def _perm_label(key):
    """Return a human-readable label for a permission key like 'pages.edit'."""
    section, _, action = key.partition('.')
    section_labels = {
        'pages': 'Pages', 'sections': 'Sections', 'appearance': 'Appearance',
        'code': 'Code', 'assets': 'Asset Library', 'calendars': 'Calendars',
        'posts': 'Posts', 'store': 'Store', 'newsletters': 'Newsletters',
        'storage': 'External Drives', 'notifications': 'Notifications',
        'payments': 'Payments',
        'ai_agents': 'AI Agents', 'forum': 'Forum', 'comments': 'Comments',
        'messages': 'Messages', 'settings': 'Settings', 'templates': 'Templates',
        'admin_users': 'Admin Users',
    }
    action_labels = {
        'view': 'view', 'edit': 'edit', 'create': 'create', 'delete': 'delete',
        'publish': 'publish', 'upload': 'upload', 'folders': 'manage folders',
        'ai_generate': 'generate with AI', 'groups': 'manage groups',
        'templates': 'use templates', 'navbar': 'edit navbar',
        'page_code': 'use page code editor', 'sections': 'edit code sections',
        'tweaks': 'use code tweaks', 'ai': 'use AI assistance',
        'events': 'manage events', 'subscriptions': 'manage subscriptions',
        'chat': 'chat with agents', 'use': 'use agents',
        'settings': 'edit settings', 'moderate': 'moderate content',
        'manage_users': 'manage users', 'delete_posts': 'delete posts',
        'download': 'download files',
        'manage': 'manage', 'send': 'send',
        'orders.fulfill': 'process orders',
        'returns': 'manage returns', 'refunds': 'issue refunds',
        'cancellations': 'approve cancellations',
        'tickets.scan': 'scan tickets', 'tickets.issue': 're-issue tickets',
        'support': 'handle customer support', 'analytics': 'view sales reports',
        'products': 'manage products', 'categories': 'manage categories',
        'reviews': 'moderate reviews',
    }
    s = section_labels.get(section, section.replace('_', ' ').title())
    a = action_labels.get(action, action.replace('_', ' '))
    return f'{s} › {a}'


