# Kept separate so admins can give someone edit access without page management.
_DRAFT_PAGES_COVERS = frozenset({
    'pages.create', 'pages.create_root', 'pages.delete', 'pages.templates',
    'pages.create_folder', 'pages.delete_folder',
})


def _is_draft_context():
    """Return True when the current request is operating on a draft website.
    Resolves the website via URL path args (website_id, page_id, section_id,
    group_id, row_id) then falls back to common form/JSON body keys.
    Result is cached in flask.g so multiple require_perm calls in the same
    request only do a single round of DB lookups."""
    from flask import g
    if hasattr(g, '_draft_ctx'):
        return g._draft_ctx

    def _int(key):
        for source in (
                request.view_args or {},  # URL path params  e.g. /section/<id>
                request.args,  # query-string     e.g. ?section_id=5
                request.form,  # form body
        ):
            v = source.get(key)
            if v is not None:
                try:
                    return int(v)
                except:
                    pass
        try:
            if request.is_json:
                data = request.get_json(silent=True) or {}
                v = data.get(key)
                if v is not None:
                    return int(v)
        except Exception:
            pass
        return None

    result = False
    try:
        wid = _int('website_id')
        pid = _int('page_id') or _int('page_content_id')
        # Some routes use first_section_id / second_section_id (swap endpoint)
        sid = (_int('section_id')
               or _int('first_section_id')
               or _int('second_section_id'))
        gid = _int('group_id')
        rid = _int('row_id')

        if wid:
            w = db.session.get(Website, wid)
            result = bool(w and w.is_draft)
        elif pid:
            p = db.session.get(PublicPageContent, pid)
            if p:
                w = db.session.get(Website, p.website_id)
                result = bool(w and w.is_draft)
        elif sid:
            s = db.session.get(PageSection, sid)
            if s and s.page_content_id:
                p = db.session.get(PublicPageContent, s.page_content_id)
                if p:
                    w = db.session.get(Website, p.website_id)
                    result = bool(w and w.is_draft)
        elif gid:
            gr = db.session.get(SectionGroup, gid)
            if gr:
                p = db.session.get(PublicPageContent, gr.page_content_id)
                if p:
                    w = db.session.get(Website, p.website_id)
                    result = bool(w and w.is_draft)
        elif rid:
            r = db.session.get(Row, rid)
            if r:
                p = db.session.get(PublicPageContent, r.page_content_id)
                if p:
                    w = db.session.get(Website, p.website_id)
                    result = bool(w and w.is_draft)
    except Exception:
        pass

    g._draft_ctx = result
    return result


def require_perm(key):
    """Decorator: blocks sub-admins who lack the given permission key.
    For JSON/AJAX requests returns a 403 JSON response with a clear message.
    For page navigations (GET) redirects to the dashboard with a flash notice.

    Special case: a sub-admin with website.draft.edit is granted all
    permissions in _DRAFT_EDIT_COVERS when the request operates on a draft
    website, so they can work freely in the draft without needing any
    live-website permissions."""

    def decorator(f):
        from functools import wraps
        @wraps(f)
        def wrapped(*args, **kwargs):
            if current_user.is_authenticated and current_user.is_sub_admin:
                _ctx_website = get_admin_website()
                _ctx_website_id = _ctx_website.id if _ctx_website else None
                if not current_user.has_permission(key, website_id=_ctx_website_id):
                    # Allow via draft permissions when acting on a draft website.
                    _draft = _is_draft_context()
                    if ((_draft
                         and key in _DRAFT_EDIT_COVERS
                         and current_user.has_permission('website.draft.edit'))
                            or (_draft
                                and key in _DRAFT_PAGES_COVERS
                                and current_user.has_permission('website.draft.pages'))):
                        pass  # grant access
                    else:
                        label = _perm_label(key)
                        msg = (f"You don't have permission to do this "
                               f"({label}). Ask your admin to grant access.")
                        wants_json = (
                                request.is_json
                                or request.method in ('POST', 'PUT', 'PATCH', 'DELETE')
                                or request.headers.get('Accept', '').startswith('application/json')
                                or request.headers.get('X-Requested-With') == 'XMLHttpRequest'
                        )
                        if wants_json:
                            return _utf8_json(
                                {'success': False, 'error': msg, 'permission_denied': True}, 403)
                        flash(msg, 'permission_denied')
                        return redirect(url_for('dashboard'))
            return f(*args, **kwargs)

        return wrapped

    return decorator


def get_admin_website():
    """Return the live website the admin is currently editing.
    Respects the session-stored editing_website_id; falls back to the primary
    (no url_prefix) site, then any live site."""
    if current_user.is_sub_admin:
        root = db.session.get(User, current_user.root_user_id)
        websites = root.websites if root else []
    else:
        websites = current_user.websites

    live = [w for w in websites if not w.is_draft]

    # Honour explicit session selection
    eid = session.get('editing_website_id')
    if eid:
        match = next((w for w in live if w.id == eid), None)
        if match:
            return match

    # Default to primary (no url_prefix), then first live
    primary = next((w for w in live if not w.url_prefix), None)
    return primary or (live[0] if live else None)


def get_admin_draft_website():
    """Return the draft website for the current admin, or None."""
    if current_user.is_sub_admin:
        root = db.session.get(User, current_user.root_user_id)
        websites = root.websites if root else []
    else:
        websites = current_user.websites
    for w in websites:
        if w.is_draft:
            return w
    return None


def get_main_admin():
    """The primary owner account (the one with no parent). After an ownership
    transfer this is NOT necessarily the lowest-id user, so recovery / admin-key
    logic must resolve it by parent_user_id, not by row order."""
    return (User.query.filter_by(parent_user_id=None)
            .order_by(User.id.asc()).first())


def _org_requires_2fa():
    """Org-wide 2FA policy, read from the anchor (primary owner). True when the
    explicit policy is on OR (legacy/back-compat) the owner has their own 2FA
    enabled — so enabling the org policy never makes the admin side LESS secure
    than the old 'owner's 2FA forces everyone' behaviour.

    Like per-user 2FA, the explicit policy auto-disables if the email server
    settings changed since it was verified (admins couldn't receive codes), and
    must be re-verified."""
    anchor = get_main_admin()
    if not anchor:
        return False
    if getattr(anchor, 'org_require_2fa', False):
        current_fp = get_email_settings_fingerprint(get_email_settings())
        if anchor.org_2fa_email_settings_version != current_fp:
            anchor.org_require_2fa = False
            anchor.org_2fa_email_settings_version = None
            anchor.org_2fa_needs_attention = True
            db.session.commit()
    return bool(anchor.org_require_2fa or anchor.two_factor_enabled)


def admin_requires_2fa(user):
    """True if this admin must pass 2FA at login: the org policy requires it, or
    they've enrolled 2FA themselves."""
    if user is None:
        return False
    return bool(getattr(user, 'two_factor_enabled', False)) or _org_requires_2fa()


def is_owner(website):
    """True if the current user (or their root admin) owns this website."""
    if website is None:
        return False
    return website.user_id == current_user.root_user_id


def owns_calendar(calendar):
    """True if the current user (or their root admin) owns this calendar.
    Calendars are user-scoped, so check user_id directly and tolerate a NULL
    website_id — external/user-scoped calendars, or ones whose owning website
    was deleted, keep user_id but have no website. Routing ownership through
    Website.query.get_or_404(calendar.website_id) 404s on those, which makes
    calendar actions (delete, add/edit event, sync) silently fail in the UI."""
    if calendar is None:
        return False
    if calendar.user_id is not None:
        return calendar.user_id == current_user.root_user_id
    if calendar.website_id is not None:
        w = Website.query.get(calendar.website_id)
        return w is not None and w.user_id == current_user.root_user_id
    return False


def _effective_perms(website_id=None):
    """Return the permissions dict governing the current sub-admin.
    When website_id is given, per-website restriction overrides
    (pages.allowed_ids, groups.allowed_ids, sections.allowed_ids,
    page_folder_perms) are merged in and take priority over global values."""
    _RESTRICTION_KEYS = ('pages.allowed_ids', 'groups.allowed_ids',
                         'sections.allowed_ids', 'page_folder_perms')
    if current_user.permission_group_id and current_user.permission_group:
        base = dict(current_user.permission_group.permissions or {})
        wp = (current_user.permission_group.website_permissions or {}).get(str(website_id), {}) if website_id else {}
    else:
        base = dict(current_user.permissions or {})
        wp = (current_user.website_permissions or {}).get(str(website_id), {}) if website_id else {}
    for key in _RESTRICTION_KEYS:
        if key in wp:
            base[key] = wp[key]
    return base


def _folder_perm(folder_id, action):
    """Return True if current sub-admin has the given action in the given page folder."""
    if not current_user.is_sub_admin:
        return True
    if not folder_id:
        return False
    w = get_admin_website()
    perms = _effective_perms(website_id=w.id if w else None)
    fp_map = perms.get('page_folder_perms') or {}
    fp = fp_map.get(str(folder_id))
    if fp is None:
        return False
    if fp == 'full':
        return True
    return action in (fp or [])


def can_access_page(page_id):
    """Sub-admins can access a page editor if they have a direct page grant,
    a folder-level edit grant, a group grant for any group on that page,
    or a section grant for any section on that page.
    All-None (no individual restrictions) means allow all pages."""
    if not current_user.is_sub_admin:
        return True

    page_obj = db.session.get(PublicPageContent, page_id)
    if page_obj and _folder_perm(page_obj.page_folder_id, 'edit'):
        return True

    w = get_admin_website()
    perms = _effective_perms(website_id=w.id if w else None)
    allowed_pages = perms.get('pages.allowed_ids')
    allowed_groups = perms.get('groups.allowed_ids')
    allowed_sections = perms.get('sections.allowed_ids')

    # No individual restrictions at all → allow all pages
    if allowed_pages is None and allowed_groups is None and allowed_sections is None:
        return True

    # Direct page grant
    if allowed_pages is not None and page_id in allowed_pages:
        return True

    # Any granted group lives on this page
    if allowed_groups:
        page_group_ids = [g.id for g in SectionGroup.query.filter_by(page_content_id=page_id).all()]
        if any(gid in allowed_groups for gid in page_group_ids):
            return True

    # Any granted section lives on this page
    if allowed_sections:
        page_section_ids = [s.id for s in PageSection.query.filter_by(page_content_id=page_id).all()]
        if any(sid in allowed_sections for sid in page_section_ids):
            return True

    return False


def can_access_section(section_id):
    """Sub-admins may be restricted to specific sections, groups, or pages.
    Page-level grants cover all current and future sections on that page.
    Group-level grants cover all current and future sections in that group.
    """
    if not current_user.is_sub_admin:
        return True

    section = db.session.get(PageSection, section_id)
    if not section:
        return False

    page_obj = db.session.get(PublicPageContent, section.page_content_id)
    if page_obj and _folder_perm(page_obj.page_folder_id, 'edit'):
        return True

    w = get_admin_website()
    perms = _effective_perms(website_id=w.id if w else None)
    allowed_sections = perms.get('sections.allowed_ids')
    allowed_groups = perms.get('groups.allowed_ids')
    allowed_pages = perms.get('pages.allowed_ids')

    if allowed_sections is None and allowed_groups is None and allowed_pages is None:
        return True

    # Page-level grant — covers all sections on this page (including new ones)
    if allowed_pages is not None and section.page_content_id in allowed_pages:
        return True

    # Group-level grant — covers all sections in this group (including new ones)
    if allowed_groups is not None and section.column and section.column.row:
        group_id = section.column.row.section_group_id
        if group_id is not None and group_id in allowed_groups:
            return True

    # Direct section grant
    if allowed_sections is not None and section_id in allowed_sections:
        return True

    return False


def can_access_folder(folder_id):
    """Sub-admins may be restricted to specific asset library folders.
    Granting access to a folder implicitly grants access to all its descendants."""
    if not current_user.is_sub_admin:
        return True
    w = get_admin_website()
    perms = _effective_perms(website_id=w.id if w else None)
    allowed = perms.get('assets.allowed_folder_ids')
    if allowed is None:
        return True
    if not allowed:
        return False
    # Direct grant
    if folder_id in allowed:
        return True
    # Walk up the ancestor chain — if any ancestor is granted, access is allowed
    folder = db.session.get(AssetFolder, folder_id)
    while folder and folder.parent_id is not None:
        if folder.parent_id in allowed:
            return True
        folder = db.session.get(AssetFolder, folder.parent_id)
    return False


def _guide_restrictions():
    """(allowed_category_ids, allowed_guide_ids) governing the current sub-admin.
    Each is either None (no restriction → all) or a list of ids. Stored globally
    in the permissions dict, like assets.allowed_folder_ids."""
    perms = _effective_perms()
    return (perms.get('guides.allowed_category_ids'),
            perms.get('guides.allowed_guide_ids'))


def _guide_unrestricted():
    """True when no guide-level restriction applies (both lists absent)."""
    cats, guides = _guide_restrictions()
    return cats is None and guides is None


def can_access_guide(guide_or_id):
    """Sub-admins may be restricted to specific guide categories and/or guides.
    A category grant covers every guide in it (current + future). No restriction
    at all (both lists None) means all guides are accessible."""
    if not current_user.is_sub_admin:
        return True
    cats, guides = _guide_restrictions()
    if cats is None and guides is None:
        return True
    guide = guide_or_id if isinstance(guide_or_id, Guide) else db.session.get(Guide, guide_or_id)
    if not guide:
        return False
    if guides is not None and guide.id in guides:
        return True
    if cats is not None and guide.category_id is not None and guide.category_id in cats:
        return True
    return False


def can_access_guide_category(category_id):
    """True if the current sub-admin may manage a specific guide category (and
    create / delete guides within it). Unrestricted users pass for any category;
    restricted users only pass for categories explicitly granted to them."""
    if not current_user.is_sub_admin:
        return True
    cats, guides = _guide_restrictions()
    if cats is None and guides is None:
        return True
    return cats is not None and category_id is not None and category_id in cats


def _quiz_restrictions():
    """(allowed_category_ids, allowed_quiz_ids) governing the current sub-admin.
    Each is either None (no restriction → all) or a list of ids. Mirrors the
    guide-access pattern; stored globally in the permissions dict."""
    perms = _effective_perms()
    return (perms.get('quizzes.allowed_category_ids'),
            perms.get('quizzes.allowed_quiz_ids'))


def _quiz_unrestricted():
    """True when no quiz-level restriction applies (both lists absent)."""
    cats, quizzes = _quiz_restrictions()
    return cats is None and quizzes is None


def can_access_quiz(quiz_or_id):
    """Sub-admins may be restricted to specific quiz categories and/or quizzes.
    A category grant covers every quiz in it (current + future). No restriction
    at all (both lists None) means all quizzes are accessible."""
    if not current_user.is_sub_admin:
        return True
    cats, quizzes = _quiz_restrictions()
    if cats is None and quizzes is None:
        return True
    quiz = quiz_or_id if isinstance(quiz_or_id, Quiz) else db.session.get(Quiz, quiz_or_id)
    if not quiz:
        return False
    if quizzes is not None and quiz.id in quizzes:
        return True
    if cats is not None and quiz.category_id is not None and quiz.category_id in cats:
        return True
    return False


def can_access_quiz_category(category_id):
    """True if the current sub-admin may manage a specific quiz category (and
    create / delete quizzes within it). Unrestricted users pass for any
    category; restricted users only pass for categories granted to them."""
    if not current_user.is_sub_admin:
        return True
    cats, quizzes = _quiz_restrictions()
    if cats is None and quizzes is None:
        return True
    return cats is not None and category_id is not None and category_id in cats


def _division_restriction():
    """The sub-admin's allowed division ids (None = no restriction → all).
    Stored globally in the permissions dict like guides.allowed_category_ids."""
    return _effective_perms().get('divisions.allowed_division_ids')


def can_access_division(division_or_id):
    """True if the current sub-admin may see/act on a division (the specific
    action — view/edit/members/delete/ksa — is gated separately by require_perm).
    This is the per-division SCOPE check: unrestricted users pass for any
    division; restricted users only pass for divisions granted to them. A
    division's KSAs inherit this scope (they live inside the division)."""
    if not current_user.is_sub_admin:
        return True
    allowed = _division_restriction()
    if allowed is None:
        return True
    did = division_or_id.id if isinstance(division_or_id, Division) else division_or_id
    return did is not None and did in allowed


def _assignable_group_restriction():
    """Permission-group ids this sub-admin may assign to others when promoting
    or editing a staff member (None = no restriction → any of the root admin's
    groups). Lets an owner stop a sub-admin from elevating someone into a group
    more powerful than the sub-admin's own. Stored in the permissions dict."""
    if not current_user.is_sub_admin:
        return None
    return _effective_perms().get('admin_users.assignable_group_ids')


def can_assign_group(group_id):
    """True if the current user may assign permission group `group_id` to a staff
    member. Unrestricted users may assign any of their groups; restricted ones
    only the groups explicitly granted to them."""
    if not current_user.is_sub_admin:
        return True
    allowed = _assignable_group_restriction()
    if allowed is None:
        return True
    try:
        return int(group_id) in allowed
    except (TypeError, ValueError):
        return False


# ── KSA / competency-matrix config helpers ───────────────────────────────────
_KSA_DEFAULT_TYPES = ['Knowledge', 'Skill', 'Ability']
# Index 0 = "none/not held"; the rest are proficiency levels 1..N.
_KSA_DEFAULT_LEVEL_LABELS = ['None', 'Novice', 'Competent', 'Proficient', 'Expert']


def _ksa_types(website):
    """The website's editable KSA type list (defaults to Knowledge/Skill/Ability)."""
    t = getattr(website, 'ksa_types', None)
    if isinstance(t, list):
        clean = [str(x).strip() for x in t if str(x).strip()]
        if clean:
            return clean
    return list(_KSA_DEFAULT_TYPES)


def _ksa_level_labels(website):
    """Ordered level labels; index = level (0 = none). Editable per website."""
    lbl = getattr(website, 'ksa_level_labels', None)
    if isinstance(lbl, list) and len(lbl) >= 2:
        return [str(x) for x in lbl]
    return list(_KSA_DEFAULT_LEVEL_LABELS)


def _ksa_level_label(website, level):
    labels = _ksa_level_labels(website)
    try:
        i = int(level)
    except (TypeError, ValueError):
        i = 0
    return labels[i] if 0 <= i < len(labels) else str(level)


_DEFAULT_DIVISION_SINGULAR = 'Division'
_DEFAULT_DIVISION_PLURAL = 'Divisions'


def _division_labels(website):
    """(singular, plural) name the site uses for a "Division" — configurable so
    a site can call them Guilds, Departments, Squads, etc. Falls back to the
    default. Returns title-cased-as-entered values."""
    s = (getattr(website, 'division_label_singular', None) or '').strip() or _DEFAULT_DIVISION_SINGULAR
    p = (getattr(website, 'division_label_plural', None) or '').strip() or _DEFAULT_DIVISION_PLURAL
    return s, p


def _division_word(website, plural=False):
    s, p = _division_labels(website)
    return p if plural else s


def _ensure_division_membership(public_user_id, division_id, status='active'):
    """Idempotently make a public user a member of a division — used when a
    division-scoped role is assigned. Never downgrades an existing membership."""
    m = DivisionMembership.query.filter_by(
        public_user_id=public_user_id, division_id=division_id).first()
    if not m:
        m = DivisionMembership(public_user_id=public_user_id,
                               division_id=division_id, status=status)
        db.session.add(m)
    return m


def _division_effective_ksas(division_id):
    """A division's effective KSA catalog: the KSAs it owns plus any KSAs shared
    into it from other divisions. Returns (owned, shared) — two ordered lists.
    Shared KSAs stay owned (and thus edited/deleted) by their origin division."""
    owned = KSA.query.filter_by(division_id=division_id).order_by(
        KSA.sort_order, KSA.name).all()
    shared_ids = [s.ksa_id for s in
                  DivisionKSAShare.query.filter_by(division_id=division_id).all()]
    shared = []
    if shared_ids:
        shared = KSA.query.filter(KSA.id.in_(shared_ids)).order_by(
            KSA.ksa_type, KSA.name).all()
    return owned, shared


def _division_ksa_folder_groups(division_id):
    """A division's effective KSAs grouped by folder for display: owned KSAs by
    their folder (folder sort_order, then an 'Unfiled' group), then a trailing
    'Shared' group for KSAs shared in from other divisions. Returns ordered
    group dicts: {'name': str|None, 'shared': bool, 'ksas': [KSA, ...]}."""
    owned, shared = _division_effective_ksas(division_id)
    folders = sorted(KSAFolder.query.filter_by(division_id=division_id).all(),
                     key=lambda f: (f.sort_order, (f.name or '').lower()))
    by_folder = {}
    for k in owned:
        by_folder.setdefault(k.folder_id, []).append(k)
    valid_ids = {f.id for f in folders}
    groups = []
    for f in folders:
        if by_folder.get(f.id):
            groups.append({'name': f.name, 'shared': False, 'ksas': by_folder[f.id]})
    unfiled = []
    for fid, klist in by_folder.items():
        if fid is None or fid not in valid_ids:
            unfiled.extend(klist)
    if unfiled:
        groups.append({'name': None, 'shared': False, 'ksas': unfiled})
    if shared:
        groups.append({'name': 'Shared', 'shared': True, 'ksas': shared})
    return groups


class PublicUser(UserMixin, db.Model):
    __tablename__ = 'public_user'

    id = db.Column(db.Integer, primary_key=True)

    website_id = db.Column(db.Integer, db.ForeignKey('website.id'), nullable=False, index=True)

    username = db.Column(db.String(80), nullable=False)
    # Optional public-facing label shown wherever this user's name appears on
    # the site. Lets users keep their login username private without changing
    # how authentication works. Falls back to `username` when NULL.
    display_username = db.Column(db.String(80), nullable=True, index=True)
    # Optional real name — collected at signup, editable later. For
    # administration and (eventually) social surfaces. Never lowercased.
    first_name = db.Column(db.String(100), nullable=True)
    last_name  = db.Column(db.String(100), nullable=True)
    email = db.Column(db.String(255), nullable=False)
    # Nullable because admin mirrors don't hold their own password — they
    # auth via the admin User row instead. Real public users always have one.
    password_hash = db.Column(db.String(255), nullable=True)

    # When set, this PublicUser is the public-facing mirror of an admin User on
    # this website. It auto-syncs username/email from the admin and cannot be
    # logged into via the public form (its password_hash is NULL).
    mirrored_admin_user_id = db.Column(
        db.Integer,
        db.ForeignKey('user.id', ondelete='CASCADE'),
        nullable=True, index=True,
    )

    email_verified = db.Column(db.Boolean, nullable=False, default=False, server_default=_sa_false())
    email_verified_at = db.Column(db.DateTime, nullable=True)
    verification_email_sent_at = db.Column(db.DateTime, nullable=True)
    password_reset_requested_at = db.Column(db.DateTime, nullable=True)
    last_verification_email_sent_at = db.Column(db.DateTime, nullable=True)

    is_banned = db.Column(db.Boolean, nullable=False, default=False, server_default=_sa_false())
    is_active_public = db.Column(db.Boolean, nullable=False, default=True, server_default=_sa_true())
    # When False, this user is hidden from the public member directory and their
    # profile page returns 404 to everyone but themselves. Opt-out (default on).
    profile_visible = db.Column(db.Boolean, nullable=False, default=True, server_default=_sa_true())

    created_at = db.Column(db.DateTime, nullable=False, default=datetime.utcnow)
    last_login_at = db.Column(db.DateTime, nullable=True)

    two_factor_enabled = db.Column(db.Boolean, nullable=False, default=False, server_default=_sa_false())
    two_factor_last_sent_at = db.Column(db.DateTime, nullable=True)

    # Phone + SMS opt-in. NULL phone or sms_opt_in=False means SMS sends to
    # this user fall back to email.
    phone_number = db.Column(db.String(40), nullable=True)
    sms_opt_in   = db.Column(db.Boolean, nullable=False, default=False,
                             server_default=_sa_false())
    sms_opted_out_at = db.Column(db.DateTime, nullable=True)

    website = db.relationship('Website', backref=db.backref('public_users', lazy=True, cascade='all, delete-orphan'))
    roles   = db.relationship('PublicUserRole', secondary='public_user_role_assignment',
                               lazy='select', backref=db.backref('members', lazy=True))
    # The admin User this row mirrors, when this is a staff mirror. Lets
    # `staff_badge_label` resolve the linked admin's permission-group name
    # straight from a template without an extra query each time.
    mirrored_admin = db.relationship('User', foreign_keys=[mirrored_admin_user_id], lazy='select')

    __table_args__ = (
        db.UniqueConstraint('website_id', 'username', name='uq_public_user_username_per_website'),
        db.UniqueConstraint('website_id', 'email', name='uq_public_user_email_per_website'),
        db.UniqueConstraint('website_id', 'mirrored_admin_user_id',
                            name='uq_public_user_admin_mirror_per_website'),
        # Login usernames are globally unique across every website so a single
        # identity can't be claimed twice (groundwork for cross-website
        # accounts). Admin mirrors are exempt — they all represent the same
        # global admin and repeat by design on each site, so the partial index
        # only covers real public users (mirrored_admin_user_id IS NULL).
        db.Index(
            'uq_public_user_username_global', 'username', unique=True,
            sqlite_where=db.text('mirrored_admin_user_id IS NULL'),
            postgresql_where=db.text('mirrored_admin_user_id IS NULL'),
        ),
    )

    @property
    def is_admin_mirror(self):
        return self.mirrored_admin_user_id is not None

    @property
    def effective_display_name(self):
        """The label rendered everywhere public. Falls back to the login
        username when the user hasn't set a separate display name."""
        return self.display_username or self.username

    @property
    def full_name(self):
        """First + last, omitting blanks; None when neither is set."""
        return ' '.join(p for p in (self.first_name, self.last_name) if p) or None

    @property
    def staff_badge_label(self):
        """The badge text shown next to this user's name in public surfaces
        (forum posts, navbar greeting, …). Returns the linked admin's
        permission-group name when this is a sub-admin mirror with a group
        assigned, 'Admin' for everyone else who's a mirror, and None for
        ordinary public users. Lets a site owner promote a public user to,
        say, "Student" or "Moderator" and have that wording — not "Admin" —
        show up wherever they post."""
        if not self.mirrored_admin_user_id:
            return None
        admin = self.mirrored_admin
        if not admin:
            return None
        # Sub-admin with a permission group → use the group's name as the badge.
        if admin.is_sub_admin and admin.permission_group_id:
            grp = admin.permission_group
            if grp and (grp.name or '').strip():
                return grp.name.strip()
        return 'Admin'

    def set_password(self, password):
        self.password_hash = generate_password_hash(password)

    def check_password(self, password):
        # Admin mirrors never authenticate through the public form.
        if not self.password_hash:
            return False
        return check_password_hash(self.password_hash, password)

    @validates('first_name', 'last_name')
    def normalize_public_name(self, key, value):
        v = (value or '').strip()
        return v or None

    @validates('username')
    def normalize_public_username(self, key, value):
        return (value or '').strip().lower()

    @validates('display_username')
    def normalize_public_display_username(self, key, value):
        v = (value or '').strip()
        return v.lower() if v else None

    @validates('email')
    def normalize_public_email(self, key, value):
        return (value or '').strip().lower()

    def __repr__(self):
        return f"<PublicUser {self.username} website={self.website_id}>"


# Many-to-many join table for public user roles
public_user_role_assignment = db.Table(
    'public_user_role_assignment',
    db.Column('user_id', db.Integer, db.ForeignKey('public_user.id', ondelete='CASCADE'), primary_key=True),
    db.Column('role_id', db.Integer, db.ForeignKey('public_user_role.id', ondelete='CASCADE'), primary_key=True),
)


class Division(db.Model):
    """An organizational unit (team / department) a public user can belong to.
    Owns a KSA catalog and members; roles can be scoped to it. Distinct from a
    role: a Division is *where you belong*, a role is *the position you hold*."""
    __tablename__ = 'division'
    id          = db.Column(db.Integer, primary_key=True)
    website_id  = db.Column(db.Integer, db.ForeignKey('website.id', ondelete='CASCADE'),
                            nullable=False, index=True)
    name        = db.Column(db.String(150), nullable=False)
    slug        = db.Column(db.String(150), nullable=False)
    description = db.Column(db.Text, nullable=True)
    color       = db.Column(db.String(20), nullable=True)
    icon        = db.Column(db.String(60), nullable=True)
    sort_order  = db.Column(db.Integer, nullable=False, default=0, server_default='0')
    created_at  = db.Column(db.DateTime, default=lambda: datetime.now(timezone.utc).replace(tzinfo=None))
    __table_args__ = (db.UniqueConstraint('website_id', 'slug', name='uq_division_site_slug'),)

    def to_dict(self):
        return {'id': self.id, 'name': self.name, 'slug': self.slug,
                'description': self.description or '', 'color': self.color or '',
                'icon': self.icon or '', 'sort_order': self.sort_order}


class RoleType(db.Model):
    """The reusable role catalog: a role's identity (name, color, job description)
    defined once per website. Divisions then *use* a role type via PublicUserRole
    (which carries the per-division requirements & member assignments). Editing a
    type propagates name/color/description to all its PublicUserRole rows."""
    __tablename__ = 'role_type'
    id          = db.Column(db.Integer, primary_key=True)
    website_id  = db.Column(db.Integer, db.ForeignKey('website.id', ondelete='CASCADE'),
                            nullable=False, index=True)
    name        = db.Column(db.String(50), nullable=False)
    color       = db.Column(db.String(20), nullable=False, default='#5eeef8')
    description = db.Column(db.Text, nullable=True)
    # Members holding this role are hidden from the default directory (e.g. Alumni).
    exclude_from_directory = db.Column(db.Boolean, nullable=False, default=False,
                                       server_default=_sa_false())
    sort_order  = db.Column(db.Integer, nullable=False, default=0, server_default='0')
    created_at  = db.Column(db.DateTime, default=lambda: datetime.now(timezone.utc).replace(tzinfo=None))
    __table_args__ = (
        db.UniqueConstraint('website_id', 'name', name='uq_role_type_name_per_website'),
    )

    def to_dict(self):
        return {'id': self.id, 'name': self.name, 'color': self.color,
                'description': self.description or '',
                'exclude_from_directory': self.exclude_from_directory}


class PublicUserRole(db.Model):
    """A division's *use* of a role type (or a site-wide role when division_id is
    NULL). Carries the per-division KSA requirements and member assignments. Its
    name/color/description/exclude_from_directory mirror its RoleType and are kept
    in sync — existing readers (matrix, profile, directory) use these directly."""
    __tablename__ = 'public_user_role'
    id         = db.Column(db.Integer, primary_key=True)
    website_id = db.Column(db.Integer, db.ForeignKey('website.id'), nullable=False, index=True)
    role_type_id = db.Column(db.Integer, db.ForeignKey('role_type.id', ondelete='CASCADE'),
                             nullable=True, index=True)
    division_id = db.Column(db.Integer, db.ForeignKey('division.id', ondelete='SET NULL'),
                            nullable=True, index=True)
    name       = db.Column(db.String(50), nullable=False)
    color      = db.Column(db.String(20), nullable=False, default='#5eeef8')
    # Optional job description — what this role is/does. Shown to members.
    description = db.Column(db.Text, nullable=True)
    # When True, members holding this role are hidden from the default public
    # members directory (e.g. "Alumni" / former members) — they remain visible
    # when this role is explicitly selected as the directory filter, so the
    # site keeps a record of past members without deleting them.
    exclude_from_directory = db.Column(db.Boolean, nullable=False, default=False,
                                       server_default=_sa_false())
    created_at = db.Column(db.DateTime, default=datetime.utcnow)
    website    = db.relationship('Website', backref=db.backref('public_roles', lazy=True, cascade='all, delete-orphan'))
    division   = db.relationship('Division', backref=db.backref('roles', lazy='dynamic'))
    role_type  = db.relationship('RoleType', backref=db.backref('uses', lazy='dynamic'))
    # Names are unique per (website, division) so different divisions can reuse
    # the same role names (Mentors, Captains, Year 1, …). Site-wide roles have
    # division_id NULL; NULLs are distinct in a UNIQUE index, so site-wide
    # name uniqueness is enforced in the route validation instead.
    __table_args__ = (
        db.UniqueConstraint('website_id', 'division_id', 'name', name='uq_pub_role_name_per_division'),
    )

    def to_dict(self):
        return {'id': self.id, 'name': self.name, 'color': self.color,
                'division_id': self.division_id, 'description': self.description or '',
                'exclude_from_directory': self.exclude_from_directory}


class DivisionMembership(db.Model):
    """Explicit membership: a public user belongs to a Division, with a status
    (active / alumni / …). A user can be in several divisions. 'alumni' lets the
    org keep former members on record (composes with role exclude_from_directory)."""
    __tablename__ = 'division_membership'
    id             = db.Column(db.Integer, primary_key=True)
    public_user_id = db.Column(db.Integer, db.ForeignKey('public_user.id', ondelete='CASCADE'),
                               nullable=False, index=True)
    division_id    = db.Column(db.Integer, db.ForeignKey('division.id', ondelete='CASCADE'),
                               nullable=False, index=True)
    status         = db.Column(db.String(20), nullable=False, default='active',
                               server_default="'active'")
    created_at     = db.Column(db.DateTime, default=lambda: datetime.now(timezone.utc).replace(tzinfo=None))
    division       = db.relationship('Division', backref=db.backref('memberships', lazy='dynamic',
                                                                    cascade='all, delete-orphan'))
    public_user    = db.relationship('PublicUser', backref=db.backref('division_memberships', lazy='dynamic',
                                                                      cascade='all, delete-orphan'))
    __table_args__ = (db.UniqueConstraint('public_user_id', 'division_id',
                                          name='uq_division_membership'),)


class KSAFolder(db.Model):
    """A named grouping for a division's KSAs (e.g. "1st year", "2nd year").
    Owned by a division; deleting a folder leaves its KSAs unfiled (SET NULL)."""
    __tablename__ = 'ksa_folder'
    id          = db.Column(db.Integer, primary_key=True)
    website_id  = db.Column(db.Integer, db.ForeignKey('website.id', ondelete='CASCADE'),
                            nullable=False, index=True)
    division_id = db.Column(db.Integer, db.ForeignKey('division.id', ondelete='CASCADE'),
                            nullable=False, index=True)
    name        = db.Column(db.String(120), nullable=False)
    sort_order  = db.Column(db.Integer, nullable=False, default=0, server_default='0')
    created_at  = db.Column(db.DateTime, default=lambda: datetime.now(timezone.utc).replace(tzinfo=None))
    division    = db.relationship('Division', backref=db.backref('ksa_folders', lazy='dynamic',
                                                                 cascade='all, delete-orphan'))

    def to_dict(self):
        return {'id': self.id, 'division_id': self.division_id,
                'name': self.name, 'sort_order': self.sort_order}


class KSA(db.Model):
    """A Knowledge / Skill / Ability item, owned by a Division (its catalog).
    `ksa_type` is a free string validated against the website's configurable
    type list (defaults to knowledge/skill/ability). Leveled 0..max_level.
    Optionally filed under a KSAFolder within its division."""
    __tablename__ = 'ksa'
    id          = db.Column(db.Integer, primary_key=True)
    website_id  = db.Column(db.Integer, db.ForeignKey('website.id', ondelete='CASCADE'),
                            nullable=False, index=True)
    division_id = db.Column(db.Integer, db.ForeignKey('division.id', ondelete='CASCADE'),
                            nullable=False, index=True)
    folder_id   = db.Column(db.Integer, db.ForeignKey('ksa_folder.id', ondelete='SET NULL'),
                            nullable=True, index=True)
    ksa_type    = db.Column(db.String(40), nullable=False, default='knowledge',
                            server_default="'knowledge'")
    name        = db.Column(db.String(200), nullable=False)
    description = db.Column(db.Text, nullable=True)
    max_level   = db.Column(db.Integer, nullable=False, default=4, server_default='4')
    sort_order  = db.Column(db.Integer, nullable=False, default=0, server_default='0')
    created_at  = db.Column(db.DateTime, default=lambda: datetime.now(timezone.utc).replace(tzinfo=None))
    division    = db.relationship('Division', backref=db.backref('ksas', lazy='dynamic',
                                                                 cascade='all, delete-orphan'))

    def to_dict(self):
        return {'id': self.id, 'division_id': self.division_id, 'ksa_type': self.ksa_type,
                'folder_id': self.folder_id,
                'name': self.name, 'description': self.description or '',
                'max_level': self.max_level, 'sort_order': self.sort_order}


class RoleKSA(db.Model):
    """A role's competency requirement: holding `role_id` is expected to hold
    `ksa_id` at `required_level`. `required` distinguishes must-have from
    recommended; `priority` (high/medium/low) orders the learning roadmap.
    Drives gap analysis in the matrix."""
    __tablename__ = 'role_ksa'
    id             = db.Column(db.Integer, primary_key=True)
    role_id        = db.Column(db.Integer, db.ForeignKey('public_user_role.id', ondelete='CASCADE'),
                               nullable=False, index=True)
    ksa_id         = db.Column(db.Integer, db.ForeignKey('ksa.id', ondelete='CASCADE'),
                               nullable=False, index=True)
    required_level = db.Column(db.Integer, nullable=False, default=1, server_default='1')
    required       = db.Column(db.Boolean, nullable=False, default=True, server_default=_sa_true())
    priority       = db.Column(db.String(10), nullable=False, default='medium',
                               server_default="'medium'")  # high | medium | low
    role           = db.relationship('PublicUserRole', backref=db.backref('ksa_requirements', lazy='dynamic',
                                                                          cascade='all, delete-orphan'))
    ksa            = db.relationship('KSA', backref=db.backref('role_requirements', lazy='dynamic',
                                                               cascade='all, delete-orphan'))
    __table_args__ = (db.UniqueConstraint('role_id', 'ksa_id', name='uq_role_ksa'),)


class KSAResource(db.Model):
    """A learning resource attached to a KSA: an external link, an internal
    Guide, or a Quiz. Powers the self-learning roadmap — clicking a skill shows
    its resources."""
    __tablename__ = 'ksa_resource'
    id            = db.Column(db.Integer, primary_key=True)
    ksa_id        = db.Column(db.Integer, db.ForeignKey('ksa.id', ondelete='CASCADE'),
                              nullable=False, index=True)
    resource_type = db.Column(db.String(16), nullable=False, default='link')  # link | guide | quiz | demonstration
    label         = db.Column(db.String(300), nullable=True)   # title / override
    url           = db.Column(db.String(1000), nullable=True)  # for link
    # For 'demonstration': what the member must demonstrate/prove to staff.
    description   = db.Column(db.Text, nullable=True)
    guide_id      = db.Column(db.Integer, db.ForeignKey('guide.id', ondelete='CASCADE'), nullable=True)
    quiz_id       = db.Column(db.Integer, db.ForeignKey('quiz.id', ondelete='CASCADE'), nullable=True)
    sort_order    = db.Column(db.Integer, nullable=False, default=0, server_default='0')
    created_at    = db.Column(db.DateTime, default=lambda: datetime.now(timezone.utc).replace(tzinfo=None))
    ksa           = db.relationship('KSA', backref=db.backref('resources', lazy='dynamic',
                                                              cascade='all, delete-orphan'))


class KSAResourceCompletion(db.Model):
    """A member's completion of a KSA resource. Used for resources that aren't
    auto-tracked: 'link' (member self-marks) and 'demonstration' (an admin signs
    off). Guide/quiz completion is derived from progress/attempts, not stored
    here. `completed_by_user_id` = the admin for demonstrations, NULL for self."""
    __tablename__ = 'ksa_resource_completion'
    id                   = db.Column(db.Integer, primary_key=True)
    public_user_id       = db.Column(db.Integer, db.ForeignKey('public_user.id', ondelete='CASCADE'),
                                     nullable=False, index=True)
    resource_id          = db.Column(db.Integer, db.ForeignKey('ksa_resource.id', ondelete='CASCADE'),
                                     nullable=False, index=True)
    completed_at         = db.Column(db.DateTime, default=lambda: datetime.now(timezone.utc).replace(tzinfo=None))
    completed_by_user_id = db.Column(db.Integer, db.ForeignKey('user.id', ondelete='SET NULL'), nullable=True)
    __table_args__       = (db.UniqueConstraint('public_user_id', 'resource_id',
                                                name='uq_ksa_resource_completion'),)


class UserKSA(db.Model):
    """A matrix cell: public user `public_user_id` holds `ksa_id` at `level`.
    Missing row = level 0 (not held). `granted_by_user_id` is the admin who set
    it, for a light audit trail."""
    __tablename__ = 'user_ksa'
    id                 = db.Column(db.Integer, primary_key=True)
    public_user_id     = db.Column(db.Integer, db.ForeignKey('public_user.id', ondelete='CASCADE'),
                                   nullable=False, index=True)
    ksa_id             = db.Column(db.Integer, db.ForeignKey('ksa.id', ondelete='CASCADE'),
                                   nullable=False, index=True)
    level              = db.Column(db.Integer, nullable=False, default=0, server_default='0')
    note               = db.Column(db.Text, nullable=True)
    # True when the member set this level themselves (vs an admin verifying it).
    # Lets the directory/matrix distinguish self-claimed from verified skills, and
    # keeps members from overwriting admin-verified levels.
    self_reported      = db.Column(db.Boolean, nullable=False, default=False,
                                   server_default=_sa_false())
    granted_by_user_id = db.Column(db.Integer, db.ForeignKey('user.id', ondelete='SET NULL'),
                                   nullable=True)
    granted_at         = db.Column(db.DateTime, default=lambda: datetime.now(timezone.utc).replace(tzinfo=None))
    updated_at         = db.Column(db.DateTime, nullable=True)
    public_user        = db.relationship('PublicUser', backref=db.backref('ksa_levels', lazy='dynamic',
                                                                          cascade='all, delete-orphan'))
    ksa                = db.relationship('KSA', backref=db.backref('user_levels', lazy='dynamic',
                                                                   cascade='all, delete-orphan'))
    __table_args__ = (db.UniqueConstraint('public_user_id', 'ksa_id', name='uq_user_ksa'),)


class DivisionKSAShare(db.Model):
    """Shares a KSA into a division other than its owner. The KSA stays owned by
    `KSA.division_id` (only the owner edits/deletes it); this row makes it appear
    in the borrowing division's catalog/matrix so that division's roles can
    require it. Member attainment (UserKSA) is global per (user, ksa), so a
    shared KSA reflects one level everywhere it appears."""
    __tablename__ = 'division_ksa_share'
    id          = db.Column(db.Integer, primary_key=True)
    division_id = db.Column(db.Integer, db.ForeignKey('division.id', ondelete='CASCADE'),
                            nullable=False, index=True)
    ksa_id      = db.Column(db.Integer, db.ForeignKey('ksa.id', ondelete='CASCADE'),
                            nullable=False, index=True)
    created_at  = db.Column(db.DateTime, default=lambda: datetime.now(timezone.utc).replace(tzinfo=None))
    division    = db.relationship('Division', backref=db.backref('ksa_shares', lazy='dynamic',
                                                                 cascade='all, delete-orphan'))
    ksa         = db.relationship('KSA', backref=db.backref('shares', lazy='dynamic',
                                                            cascade='all, delete-orphan'))
    __table_args__ = (db.UniqueConstraint('division_id', 'ksa_id', name='uq_division_ksa_share'),)


class ForumThread(db.Model):
    __tablename__ = 'forum_thread'

    id = db.Column(db.Integer, primary_key=True)

    website_id = db.Column(db.Integer, db.ForeignKey('website.id'), nullable=False, index=True)
    public_user_id = db.Column(db.Integer, db.ForeignKey('public_user.id'), nullable=True, index=True)

    title = db.Column(db.String(180), nullable=False)
    body = db.Column(db.Text, nullable=False)

    is_locked = db.Column(db.Boolean, nullable=False, default=False, server_default=_sa_false())
    is_hidden = db.Column(db.Boolean, nullable=False, default=False, server_default=_sa_false())
    is_pinned = db.Column(db.Boolean, nullable=False, default=False, server_default=_sa_false())

    created_at = db.Column(db.DateTime, nullable=False, default=datetime.utcnow)
    updated_at = db.Column(db.DateTime, nullable=False, default=datetime.utcnow, onupdate=datetime.utcnow)

    ip_address = db.Column(db.String(64), nullable=True)
    user_agent = db.Column(db.Text, nullable=True)

    website = db.relationship('Website', backref=db.backref('forum_threads', lazy=True, cascade='all, delete-orphan'))
    author = db.relationship('PublicUser', backref=db.backref('forum_threads', lazy=True))

    reply_count = db.Column(db.Integer, nullable=False, default=0, server_default='0')
    vote_count_cached = db.Column(db.Integer, nullable=False, default=0, server_default='0')

    __table_args__ = (
        db.Index('ix_forum_thread_website_hidden_updated', 'website_id', 'is_hidden', 'updated_at'),
        db.Index('ix_forum_thread_website_hidden_created', 'website_id', 'is_hidden', 'created_at'),
        db.Index('ix_forum_thread_website_hidden_votes', 'website_id', 'is_hidden', 'vote_count_cached'),
        db.Index('ix_forum_thread_website_hidden_replies', 'website_id', 'is_hidden', 'reply_count'),
    )

    def visible_reply_count(self):
        return ForumReply.query.filter_by(
            thread_id=self.id,
            is_hidden=False
        ).count()

    def vote_count(self):
        return ForumThreadVote.query.filter_by(thread_id=self.id).count()

    def user_has_voted(self, public_user):
        if not public_user:
            return False

        return ForumThreadVote.query.filter_by(
            thread_id=self.id,
            public_user_id=public_user.id
        ).first() is not None

    def __repr__(self):
        return f"<ForumThread {self.id} {self.title}>"


class EmailServerSettings(db.Model):
    id = db.Column(db.Integer, primary_key=True)

    label = db.Column(db.String(200), nullable=False, default='Default', server_default=db.text("'Default'"))
    is_default = db.Column(db.Boolean, nullable=False, default=False, server_default=_sa_false())

    smtp_host = db.Column(db.String(255), nullable=False)
    smtp_port = db.Column(db.Integer, nullable=False, default=587)
    smtp_username = db.Column(db.String(255), nullable=False)
    smtp_password = db.Column(db.String(255), nullable=False)

    use_tls = db.Column(db.Boolean, default=True)
    use_ssl = db.Column(db.Boolean, default=False)

    from_email = db.Column(db.String(255), nullable=False)
    from_name = db.Column(db.String(255), nullable=True)

    is_active = db.Column(db.Boolean, default=True)

    def __repr__(self):
        return f"<EmailServerSettings {self.id} {self.label!r}>"


class ForumReply(db.Model):
    __tablename__ = 'forum_reply'

    id = db.Column(db.Integer, primary_key=True)

    thread_id = db.Column(db.Integer, db.ForeignKey('forum_thread.id'), nullable=False, index=True)
    website_id = db.Column(db.Integer, db.ForeignKey('website.id'), nullable=False, index=True)
    public_user_id = db.Column(db.Integer, db.ForeignKey('public_user.id'), nullable=True, index=True)

    body = db.Column(db.Text, nullable=False)

    is_hidden = db.Column(db.Boolean, nullable=False, default=False, server_default=_sa_false())

    vote_count_cached = db.Column(db.Integer, nullable=False, default=0, server_default='0', index=True)

    created_at = db.Column(db.DateTime, nullable=False, default=datetime.utcnow)
    updated_at = db.Column(db.DateTime, nullable=False, default=datetime.utcnow, onupdate=datetime.utcnow)

    ip_address = db.Column(db.String(64), nullable=True)
    user_agent = db.Column(db.Text, nullable=True)

    thread = db.relationship('ForumThread', backref=db.backref('replies', lazy=True, cascade='all, delete-orphan'))
    website = db.relationship('Website', backref=db.backref('forum_replies', lazy=True, cascade='all, delete-orphan'))
    author = db.relationship('PublicUser', backref=db.backref('forum_replies', lazy=True))

    __table_args__ = (
        db.Index('ix_forum_reply_thread_hidden_created', 'thread_id', 'is_hidden', 'created_at'),
        db.Index('ix_forum_reply_website_hidden_created', 'website_id', 'is_hidden', 'created_at'),
    )

    def vote_count(self):
        return ForumReplyVote.query.filter_by(reply_id=self.id).count()

    def user_has_voted(self, public_user):
        if not public_user:
            return False

        return ForumReplyVote.query.filter_by(
            reply_id=self.id,
            public_user_id=public_user.id
        ).first() is not None

    def __repr__(self):
        return f"<ForumReply {self.id} thread={self.thread_id}>"


class ForumThreadVote(db.Model):
    __tablename__ = 'forum_thread_vote'

    id = db.Column(db.Integer, primary_key=True)

    thread_id = db.Column(
        db.Integer,
        db.ForeignKey('forum_thread.id'),
        nullable=False,
        index=True
    )

    website_id = db.Column(
        db.Integer,
        db.ForeignKey('website.id'),
        nullable=False,
        index=True
    )

    public_user_id = db.Column(
        db.Integer,
        db.ForeignKey('public_user.id'),
        nullable=False,
        index=True
    )

    created_at = db.Column(db.DateTime, nullable=False, default=datetime.utcnow, index=True)

    thread = db.relationship(
        'ForumThread',
        backref=db.backref('votes', lazy=True, cascade='all, delete-orphan')
    )

    public_user = db.relationship(
        'PublicUser',
        backref=db.backref('thread_votes', lazy=True, cascade='all, delete-orphan')
    )

    __table_args__ = (
        db.UniqueConstraint(
            'thread_id',
            'public_user_id',
            name='uq_forum_thread_vote_once_per_user'
        ),
        db.Index('ix_forum_thread_vote_thread_user', 'thread_id', 'public_user_id'),
        db.Index('ix_forum_thread_vote_website_thread', 'website_id', 'thread_id'),
    )


class ForumReplyVote(db.Model):
    __tablename__ = 'forum_reply_vote'

    id = db.Column(db.Integer, primary_key=True)

    reply_id = db.Column(
        db.Integer,
        db.ForeignKey('forum_reply.id'),
        nullable=False,
        index=True
    )

    website_id = db.Column(
        db.Integer,
        db.ForeignKey('website.id'),
        nullable=False,
        index=True
    )

    public_user_id = db.Column(
        db.Integer,
        db.ForeignKey('public_user.id'),
        nullable=False,
        index=True
    )

    created_at = db.Column(db.DateTime, nullable=False, default=datetime.utcnow, index=True)

    reply = db.relationship(
        'ForumReply',
        backref=db.backref('votes', lazy=True, cascade='all, delete-orphan')
    )

    public_user = db.relationship(
        'PublicUser',
        backref=db.backref('reply_votes', lazy=True, cascade='all, delete-orphan')
    )

    __table_args__ = (
        db.UniqueConstraint(
            'reply_id',
            'public_user_id',
            name='uq_forum_reply_vote_once_per_user'
        ),
        db.Index('ix_forum_reply_vote_reply_user', 'reply_id', 'public_user_id'),
        db.Index('ix_forum_reply_vote_website_reply', 'website_id', 'reply_id'),
    )


class PageComment(db.Model):
    __tablename__ = 'page_comment'

    id = db.Column(db.Integer, primary_key=True)

    website_id = db.Column(db.Integer, db.ForeignKey('website.id'), nullable=False, index=True)
    page_id = db.Column(db.Integer, db.ForeignKey('public_page_content.id'), nullable=False, index=True)
    section_id = db.Column(db.Integer, db.ForeignKey('page_section.id'), nullable=False, index=True)

    public_user_id = db.Column(db.Integer, db.ForeignKey('public_user.id'), nullable=True, index=True)

    display_name = db.Column(db.String(120), nullable=False)
    body = db.Column(db.Text, nullable=False)

    is_hidden = db.Column(db.Boolean, nullable=False, default=False, server_default=_sa_false(), index=True)
    is_approved = db.Column(db.Boolean, nullable=False, default=True, server_default=_sa_true(), index=True)

    ip_address = db.Column(db.String(64), nullable=True)
    user_agent = db.Column(db.Text, nullable=True)

    created_at = db.Column(db.DateTime, nullable=False, default=datetime.utcnow, index=True)
    updated_at = db.Column(db.DateTime, nullable=False, default=datetime.utcnow, onupdate=datetime.utcnow)

    website = db.relationship('Website', backref=db.backref('page_comments', lazy=True, cascade='all, delete-orphan'))
    page = db.relationship('PublicPageContent',
                           backref=db.backref('page_comments', lazy=True, cascade='all, delete-orphan'))
    section = db.relationship('PageSection', backref=db.backref('comments', lazy=True, cascade='all, delete-orphan'))
    author = db.relationship('PublicUser', backref=db.backref('page_comments', lazy=True))

    like_count_cached = db.Column(db.Integer, nullable=False, default=0, server_default='0', index=True)

    def like_count(self):
        return self.like_count_cached or 0

    def user_has_liked(self, public_user):
        if not public_user:
            return False

        return PageCommentLike.query.filter_by(
            comment_id=self.id,
            public_user_id=public_user.id
        ).first() is not None

    __table_args__ = (
        db.Index('ix_page_comment_section_visible_created', 'section_id', 'is_hidden', 'is_approved', 'created_at'),
        db.Index('ix_page_comment_page_section_created', 'page_id', 'section_id', 'created_at'),
    )

    def __repr__(self):
        return f"<PageComment {self.id} section={self.section_id}>"


