    __tablename__ = 'guide'
    id              = db.Column(db.Integer, primary_key=True)
    website_id      = db.Column(db.Integer, db.ForeignKey('website.id', ondelete='CASCADE'),
                                nullable=False, index=True)
    title           = db.Column(db.String(200), nullable=False)
