def update_contact_section(section, form_data):
    contact_form_title = form_data.get('contact_form_title')
    contact_email = form_data.get('contact_email')
    contact_form_enabled = form_data.get('contact_form_enabled') == 'on'

    # Per-section submission cooldown (hours). Blank falls back to the default;
    # 0 disables the limit. Clamp to a sane range (0 .. one year).
    raw_cooldown = (form_data.get('contact_cooldown_hours') or '').strip()
    if raw_cooldown == '':
        cooldown_hours = _CONTACT_RATE_LIMIT_HOURS
    else:
        try:
            cooldown_hours = max(0.0, min(8760.0, float(raw_cooldown)))
        except (TypeError, ValueError):
            cooldown_hours = _CONTACT_RATE_LIMIT_HOURS

    section.content = {
        'title': contact_form_title,
        'email': contact_email,
        'enabled': contact_form_enabled,
        'cooldown_hours': cooldown_hours,
        'fields': _parse_contact_custom_fields(form_data.get('contact_custom_fields')),
    }
    return section


# Custom contact-form fields the admin can add (beyond Email/Subject/Message).
_CONTACT_FIELD_TYPES = {'text', 'email', 'tel', 'number', 'textarea'}


def _parse_contact_custom_fields(raw):
    """Validate the JSON list of admin-defined custom fields from the editor.
    Returns a clean list of {label, type, required}; drops malformed/empty rows."""
    if not raw:
        return []
    try:
        items = json.loads(raw)
    except (ValueError, TypeError):
        return []
    if not isinstance(items, list):
        return []
    cleaned = []
    for it in items:
        if not isinstance(it, dict):
            continue
        label = (it.get('label') or '').strip()[:100]
        if not label:
            continue
        ftype = it.get('type') if it.get('type') in _CONTACT_FIELD_TYPES else 'text'
        cleaned.append({'label': label, 'type': ftype, 'required': bool(it.get('required'))})
        if len(cleaned) >= 20:  # sane cap
            break
    return cleaned


def update_product_grid_section(section, form_data):
    import json as _json
    source = form_data.get('pg_source') or 'all'
    raw_ids = form_data.get('pg_product_ids') or '[]'
    try:
        product_ids = _json.loads(raw_ids)
    except Exception:
        product_ids = []
    section.content = {
        'source':      source,
        'category_id': int(form_data.get('pg_category_id') or 0) or None,
        'product_ids': product_ids if source == 'manual' else [],
        'title':            (form_data.get('pg_title') or '').strip()[:120] or None,
        'layout':           form_data.get('pg_layout') or 'grid',
        'columns':          int(form_data.get('pg_columns') or 3),
        'limit':            int(form_data.get('pg_limit') or 12),
        'show_price':       form_data.get('pg_show_price') != 'off',
        'show_description': form_data.get('pg_show_description') == 'on',
        'show_add_to_cart': form_data.get('pg_show_cart') != 'off',
    }
    return section


