    u = _get_owned_public_user(user_id)
    blocked = _reject_if_admin_mirror(u)
    if blocked:
        return blocked
    u.is_active_public = not u.is_active_public
    db.session.commit()
    return _utf8_json({'success': True, 'is_active': u.is_active_public})


