@app.route('/admin/posts/<int:cid>/articles/save', methods=['POST'])
@login_required
@require_perm('posts.edit')
def admin_post_save(cid):
    collection = PostCollection.query.get_or_404(cid)
    website = get_admin_website()
    if not website or not is_owner(website):
        return _utf8_json({'success': False, 'error': 'Unauthorized'}, 403)
    data = request.get_json() or {}
    title = (data.get('title') or '').strip()
    if not title:
        return _utf8_json({'success': False, 'error': 'Title is required'}, 400)
    comments_enabled = bool(data.get('comments_enabled', False))
    comments_require_login = bool(data.get('comments_require_login', False))
    comments_moderation    = bool(data.get('comments_moderation', False))

    # Optional override for published_at — lets admins backdate posts when
    # importing older content. Empty string clears the override (i.e. defers
    # to the publish action). Always stored naive, in the admin's local tz,
    # matching the rest of the codebase's datetime convention.
    raw_pub = (data.get('published_at') or '').strip()
    published_at_override = None
    clear_published_at = False
    if 'published_at' in data:
        if raw_pub:
            try:
                published_at_override = datetime.fromisoformat(raw_pub)
                # Drop tz if the browser sent one (datetime-local doesn't,
                # but be defensive against future client changes).
                if published_at_override.tzinfo is not None:
                    published_at_override = published_at_override.replace(tzinfo=None)
            except ValueError:
                return _utf8_json({'success': False, 'error': 'Invalid publish date'}, 400)
        else:
            clear_published_at = True

    pid = data.get('id')
    if pid:
        post = Post.query.filter_by(id=int(pid), collection_id=cid).first_or_404()
        # Slug: use provided or keep existing
        raw_slug = (data.get('slug') or '').strip()
        if raw_slug:
            base_slug = _slugify_post(raw_slug)
            post.slug = _unique_post_slug(cid, base_slug, exclude_id=post.id)
        post.title = title
        post.excerpt = (data.get('excerpt') or '').strip() or None
        post.content = data.get('content') or None
        post.cover_image_url = (data.get('cover_image_url') or '').strip() or None
        post.comments_enabled = comments_enabled
        post.comments_require_login = comments_require_login
        post.comments_moderation    = comments_moderation
        post.updated_at = datetime.now(timezone.utc).replace(tzinfo=None)
        # Apply the publish-date override last so it survives any of the
        # field assignments above. A set value backdates (or future-dates) a
        # draft as well — clearing reverts to "publish action will set it".
        if published_at_override is not None:
            post.published_at = published_at_override
        elif clear_published_at:
            post.published_at = None
    else:
        raw_slug = (data.get('slug') or '').strip()
        base_slug = _slugify_post(raw_slug if raw_slug else title)
        slug = _unique_post_slug(cid, base_slug)
        post = Post(
            collection_id=cid,
            website_id=website.id,
            title=title,
            slug=slug,
            excerpt=(data.get('excerpt') or '').strip() or None,
            content=data.get('content') or None,
            cover_image_url=(data.get('cover_image_url') or '').strip() or None,
            comments_enabled=comments_enabled,
            comments_require_login=comments_require_login,
            comments_moderation=comments_moderation,
            published_at=published_at_override,
            status='draft',
        )
        db.session.add(post)

    db.session.commit()
    return _utf8_json({'success': True, 'post': {
        'id': post.id,
        'slug': post.slug,
        'status': post.status,
    }})


@app.route('/admin/posts/<int:cid>/articles/<int:pid>/publish', methods=['POST'])
@login_required
@require_perm('posts.publish')
def admin_post_publish(cid, pid):
    collection = PostCollection.query.get_or_404(cid)
    admin_website = get_admin_website()
    if not admin_website or not is_owner(admin_website):
        return _utf8_json({'success': False, 'error': 'Unauthorized'}, 403)
    post = Post.query.filter_by(id=pid, collection_id=cid).first_or_404()
    was_published_before = bool(post.published_at)
    post.status = 'published'
    if not post.published_at:
        post.published_at = datetime.now(timezone.utc).replace(tzinfo=None)
    post.updated_at = datetime.now(timezone.utc).replace(tzinfo=None)
    db.session.commit()
    # Fire notifications only on the FIRST publish so re-publishing a post
    # after an unpublish/republish cycle doesn't double-ping. The dispatcher
    # resolves the URL per rule based on each rule's website filter, so the
    # site shown in Discord follows what the admin actually configured the
    # rule for (rather than where the post was created).
    if not was_published_before:
        dispatch_notification('post.published', post=post)
    return _utf8_json({'success': True, 'status': post.status, 'slug': post.slug})


