# ════════════════════════════════════════════════════════════════════════════
# Code runner (Piston) — sandboxed execution for `coding` quiz questions
# ════════════════════════════════════════════════════════════════════════════

_PISTON_DEFAULT_URL = (os.environ.get('PISTON_URL') or 'https://emkc.org/api/v2/piston').rstrip('/')

# Our language ids → (Piston language name, source filename). Java's filename is
# overridden to match its public class (see _piston_filename).
_CODE_LANGUAGES = {
    'python':     {'label': 'Python',     'piston': 'python',     'file': 'main.py',  'compiled': False},
    'javascript': {'label': 'JavaScript', 'piston': 'javascript', 'file': 'main.js',  'compiled': False},
    'java':       {'label': 'Java',       'piston': 'java',       'file': 'Main.java', 'compiled': True},
    'c':          {'label': 'C',          'piston': 'c',          'file': 'main.c',   'compiled': True},
    'cpp':        {'label': 'C++',        'piston': 'c++',        'file': 'main.cpp', 'compiled': True},
}

# Trivial "print ok" programs, one per language, used by the runner self-test.
_CODE_HELLO = {
    'python':     "print('ok')",
    'javascript': "console.log('ok')",
    'java':       'public class Main { public static void main(String[] a){ System.out.println("ok"); } }',
    'c':          '#include <stdio.h>\nint main(){ printf("ok\\n"); return 0; }',
    'cpp':        '#include <iostream>\nint main(){ std::cout << "ok" << std::endl; return 0; }',
}

_PISTON_RUNTIMES_CACHE = {}  # url -> {'at': ts, 'map': {piston_lang: version}}


def _piston_runtimes_summary(url):
    """Fresh '<language> <version>' strings for what the runner reports as
    installed — for the settings UI. Returns (list, error_or_None)."""
    import requests as _rq
    try:
        resp = _rq.get(f'{url}/runtimes', timeout=10)
        resp.raise_for_status()
        out = []
        for rt in resp.json():
            lang = rt.get('language')
            ver = rt.get('version')
            if lang:
                out.append(f'{lang} {ver}' if ver else lang)
        return out, None
    except Exception as e:
        return [], str(e)


def _code_runner_url_for_user(user_id):
    s = CodeRunnerSettings.query.filter_by(user_id=user_id).first() if user_id else None
    url = (s.piston_url or '').strip() if s else ''
    return (url or _PISTON_DEFAULT_URL).rstrip('/')


def _code_runner_url_for_website(website):
    return _code_runner_url_for_user(website.user_id if website else None)


def _piston_resolve_version(url, piston_lang):
    """Latest available version for a Piston language, cached ~10 min per URL."""
    import time as _time
    entry = _PISTON_RUNTIMES_CACHE.get(url)
    if not entry or (_time.time() - entry['at']) > 600:
        import requests as _rq
        rmap = {}
        try:
            resp = _rq.get(f'{url}/runtimes', timeout=10)
            resp.raise_for_status()
            for rt in resp.json():
                name = rt.get('language')
                ver = rt.get('version')
                aliases = rt.get('aliases') or []
                for key in [name] + aliases:
                    if key and (key not in rmap):
                        rmap[key] = ver
        except Exception:
            rmap = {}
        entry = {'at': _time.time(), 'map': rmap}
        _PISTON_RUNTIMES_CACHE[url] = entry
    return entry['map'].get(piston_lang)


def _piston_filename(language, source):
    spec = _CODE_LANGUAGES.get(language) or {}
    fname = spec.get('file', 'main.txt')
    if language == 'java':
        m = re.search(r'public\s+(?:final\s+|abstract\s+)?class\s+([A-Za-z_]\w*)', source or '')
        if m:
            fname = f'{m.group(1)}.java'
    return fname


def _run_code(url, language, source, stdin=''):
    """Execute one program via Piston. Returns a normalized dict:
    {ok, compile_ok, compile_output, stdout, stderr, code, error}. `ok` is the
    transport success (the call completed), not whether the program passed."""
    spec = _CODE_LANGUAGES.get(language)
    if not spec:
        return {'ok': False, 'error': 'Unsupported language.'}
    version = _piston_resolve_version(url, spec['piston'])
    if not version:
        return {'ok': False, 'error': 'Code runner is unavailable or the language is not installed.'}
    import requests as _rq
    # NOTE: we deliberately don't send compile_timeout/run_timeout — a
    # self-hosted Piston rejects values above its configured maximum with a
    # 400, so we let the instance apply its own limits.
    payload = {
        'language': spec['piston'], 'version': version,
        'files': [{'name': _piston_filename(language, source), 'content': source or ''}],
        'stdin': stdin or '',
    }
    try:
        resp = _rq.post(f'{url}/execute', json=payload, timeout=25)
    except Exception as e:
        return {'ok': False, 'error': f'Could not reach the code runner at {url}/execute: {e}'}
    if resp.status_code == 429:
        return {'ok': False, 'error': 'Code runner is busy (rate limited). Please try again in a moment.'}
    if not resp.ok:
        # Surface Piston's own message (e.g. "run_timeout exceeds maximum",
        # "<lang>-<ver> runtime is unknown") instead of a bare status code.
        detail = ''
        try:
            j = resp.json()
            detail = j.get('message') or j.get('error') or ''
        except Exception:
            detail = (resp.text or '').strip()
        detail = (detail or 'no error body')[:300]
        return {'ok': False, 'error': f'Runner returned HTTP {resp.status_code}: {detail}'}
    try:
        data = resp.json()
    except Exception as e:
        return {'ok': False, 'error': f'Runner returned a non-JSON response: {e}'}
    compile_stage = data.get('compile') or {}
    run_stage = data.get('run') or {}
    compile_code = compile_stage.get('code')
    compile_out = (compile_stage.get('stderr') or compile_stage.get('output') or '').strip()
    return {
        'ok': True,
        'compile_ok': (compile_code in (0, None)),
        'compile_output': compile_out,
        'stdout': run_stage.get('stdout') or '',
        'stderr': run_stage.get('stderr') or '',
        'code': run_stage.get('code'),
        'error': None,
    }


def _normalize_code_output(s):
    """Whitespace-tolerant comparison: trim trailing spaces per line and drop
    trailing blank lines."""
    lines = [ln.rstrip() for ln in (s or '').replace('\r\n', '\n').split('\n')]
    while lines and lines[-1] == '':
        lines.pop()
    return '\n'.join(lines)


def _code_compiles_cleanly(language, res):
    """"Correctly written" check for compile-mode coding questions. Compiled
    languages pass when the compile stage succeeded; interpreted languages pass
    when running surfaced no syntax/parse error (runtime errors still count as
    'written correctly')."""
    spec = _CODE_LANGUAGES.get(language) or {}
    if spec.get('compiled'):
        return bool(res.get('compile_ok'))
    stderr = (res.get('stderr') or '') + '\n' + (res.get('compile_output') or '')
    return ('SyntaxError' not in stderr and 'IndentationError' not in stderr)


# ── Public quiz + progress API ──────────────────────────────────────────────

def _set_visitor_cookie(resp, visitor_id):
    resp.set_cookie('uwebia_asset_visitor_id', visitor_id,
                    max_age=60 * 60 * 24 * 365, httponly=True, samesite='Lax')
    return resp


def _grade_quiz(quiz, submitted):
    """Grade a submission server-side. `submitted` maps question id -> answer
    (option id for single/true_false, list of ids for multi, string for
    short_text). Returns (score, max_score, results)."""
    score = max_score = 0
    results = []
    # Coding questions run via the sandboxed runner; resolve its URL lazily so
    # quizzes with no coding question pay no cost.
    _runner = {}

    def _runner_url():
        if 'url' not in _runner:
            _runner['url'] = _code_runner_url_for_website(db.session.get(Website, quiz.website_id))
        return _runner['url']

    for q in quiz.questions.order_by(QuizQuestion.sort_order):
        max_score += q.points
        cfg = q._config()
        ans = submitted.get(str(q.id), submitted.get(q.id))
        detail = {'question_id': q.id}
        correct = False
        earned = None  # set explicitly only for partial-credit types
        if q.question_type in ('single_choice', 'true_false', 'image_choice') and not cfg.get('multiple'):
            correct_ids = [o['id'] for o in cfg.get('options', []) if o.get('correct')]
            try:
                sel = int(ans) if ans not in (None, '') else None
            except (ValueError, TypeError):
                sel = None
            correct = sel is not None and sel in correct_ids
            detail['correct_option_ids'] = correct_ids
        elif q.question_type == 'multi_choice' or (q.question_type == 'image_choice' and cfg.get('multiple')):
            correct_ids = set(o['id'] for o in cfg.get('options', []) if o.get('correct'))
            try:
                sel = set(int(x) for x in (ans or []))
            except (ValueError, TypeError):
                sel = set()
            correct = bool(correct_ids) and sel == correct_ids
            detail['correct_option_ids'] = list(correct_ids)
        elif q.question_type == 'fill_blank':
            # Partial credit: each blank scores independently.
            blanks = cfg.get('blanks', [])
            answers = ans if isinstance(ans, list) else []
            per_blank = []
            got = 0
            for i, b in enumerate(blanks):
                raw = answers[i] if i < len(answers) else ''
                val = raw.strip() if isinstance(raw, str) else ''
                cs = b.get('case_sensitive')
                needle = val if cs else val.lower()
                haystack = b.get('accepted', []) if cs else [a.lower() for a in b.get('accepted', [])]
                ok = needle != '' and needle in haystack
                per_blank.append(ok)
                if ok:
                    got += 1
            total = len(blanks)
            earned = round(q.points * got / total) if total else 0
            correct = total > 0 and got == total
            detail['blank_results'] = per_blank
            detail['blank_accepted'] = [b.get('accepted', []) for b in blanks]
        elif q.question_type == 'matching':
            pairs = cfg.get('pairs', [])
            sub = ans if isinstance(ans, dict) else {}
            all_ok = bool(pairs)
            for p in pairs:
                chosen = sub.get(str(p['left_id']), sub.get(p['left_id']))
                try:
                    chosen = int(chosen)
                except (TypeError, ValueError):
                    chosen = None
                if chosen != p['right_id']:
                    all_ok = False
            correct = all_ok
            detail['correct_pairs'] = {str(p['left_id']): p['right_id'] for p in pairs}
        elif q.question_type == 'ordering':
            order = cfg.get('answer_order', [])
            sub = ans if isinstance(ans, list) else []
            try:
                sub_ids = [int(x) for x in sub]
            except (TypeError, ValueError):
                sub_ids = []
            correct = bool(order) and sub_ids == order
            detail['answer_order'] = order
        elif q.question_type == 'coding':
            code = ans if isinstance(ans, str) else ''
            language = cfg.get('language', 'python')
            mode = cfg.get('mode', 'run')
            detail['language'] = language
            detail['mode'] = mode
            if not code.strip():
                correct = False
            else:
                url = _runner_url()
                if mode == 'compile':
                    res = _run_code(url, language, code)
                    if not res.get('ok'):
                        correct = False
                        detail['runner_error'] = res.get('error')
                    else:
                        correct = _code_compiles_cleanly(language, res)
                        detail['compile_output'] = (res.get('compile_output')
                                                    or (res.get('stderr') if not correct else ''))[:4000]
                else:  # run against test cases — all must pass
                    cases = cfg.get('test_cases') or []
                    tests, tests_expected = [], []
                    all_ok = bool(cases)
                    for tc in cases:
                        res = _run_code(url, language, code, tc.get('stdin', ''))
                        if not res.get('ok'):
                            # Transport failure (runner down/rate-limited) — stop
                            # rather than timing out once per remaining case.
                            all_ok = False
                            detail['runner_error'] = res.get('error')
                            break
                        got = _normalize_code_output(res.get('stdout'))
                        exp = _normalize_code_output(tc.get('expected', ''))
                        passed = res.get('compile_ok') and (got == exp)
                        if not passed:
                            all_ok = False
                        tests.append({
                            'passed': bool(passed),
                            'stdout': (res.get('stdout') or '')[:4000],
                            'stderr': ((res.get('stderr') or '') or (res.get('compile_output') or ''))[:4000],
                        })
                        tests_expected.append(tc.get('expected', ''))
                    correct = all_ok
                    detail['tests'] = tests
                    detail['tests_expected'] = tests_expected
        else:  # short_text
            accepted = cfg.get('accepted', [])
            cs = cfg.get('case_sensitive')
            val = ans.strip() if isinstance(ans, str) else ''
            needle = val if cs else val.lower()
            haystack = accepted if cs else [a.lower() for a in accepted]
            correct = needle != '' and needle in haystack
            detail['accepted'] = accepted
        if earned is None:
            earned = q.points if correct else 0
        score += earned
        detail['earned'] = earned
        detail['correct'] = correct
        results.append(detail)
    return score, max_score, results


def _quiz_best_score(quiz_id, public_user, visitor_hash):
    q = QuizAttempt.query.filter_by(quiz_id=quiz_id)
    if public_user:
        q = q.filter(db.or_(QuizAttempt.public_user_id == public_user.id,
                            QuizAttempt.visitor_id_hash == visitor_hash))
    else:
        q = q.filter(QuizAttempt.visitor_id_hash == visitor_hash)
    best = q.order_by(QuizAttempt.score.desc()).first()
    return best.score if best else 0


def _live_website_for(model_obj):
    """Resolve the live Website that owns a quiz/guide, or abort 404. Avoids
    URL-prefix ambiguity — the owning site is derived from the object itself."""
    website = Website.query.get(model_obj.website_id)
    if not website or not website.is_live:
        abort(404)
    return website


def _quiz_draft_for(quiz_id, public_user, visitor_hash):
    """The saved in-progress draft for this quiz and identity, or None.
    Prefers a draft tied to the logged-in user (resumes across devices),
    falling back to one keyed on the current device's visitor hash."""
    if public_user:
        rec = QuizDraft.query.filter_by(quiz_id=quiz_id, public_user_id=public_user.id) \
            .order_by(QuizDraft.updated_at.desc()).first()
        if rec:
            return rec
    if visitor_hash:
        return QuizDraft.query.filter_by(quiz_id=quiz_id, visitor_id_hash=visitor_hash).first()
    return None


@app.route('/quiz/<int:qid>')
def public_quiz_page(qid):
    """Standalone takeable quiz page — gives quizzes a public URL so they can be
    attached as a KSA learning resource (or shared directly)."""
    quiz = Quiz.query.get_or_404(qid)
    website = _live_website_for(quiz)
    return render_template('public_quiz_page.html', website=website, quiz=quiz,
                           public_user=_public_user_for_website(website))


@app.route('/api/quizzes/<int:qid>')
def public_quiz_get(qid):
    quiz = Quiz.query.get_or_404(qid)
    website = _live_website_for(quiz)
    questions = [q.to_public_dict() for q in quiz.questions.order_by(QuizQuestion.sort_order)]
    if quiz.shuffle_questions:
        import random as _random
        _random.shuffle(questions)

    # Pre-fill any saved in-progress answers so the reader resumes where they
    # left off. Resolving the visitor here (and setting the cookie) keeps the
    # anonymous identity stable between load, autosave and submit.
    public_user = _public_user_for_website(website)
    visitor_id, should_set_cookie = get_or_create_asset_visitor_id()
    visitor_hash = hash_asset_visitor_id(visitor_id)
    draft = _quiz_draft_for(quiz.id, public_user, visitor_hash)

    resp = _utf8_json({'success': True, 'quiz': {
        'id': quiz.id, 'title': quiz.title, 'description': quiz.description or '',
        'questions': questions,
        'draft': (draft.answers or {}) if draft else None}})
    return _set_visitor_cookie(resp, visitor_id) if should_set_cookie else resp


@app.route('/api/quizzes/<int:qid>/draft', methods=['POST'])
def public_quiz_save_draft(qid):
    """Autosave a reader's in-progress answers (debounced from the client) so
    they can resume the quiz later. Upserts one row per quiz per identity."""
    quiz = Quiz.query.get_or_404(qid)
    website = _live_website_for(quiz)
    data = request.get_json() or {}
    answers = data.get('answers')
    if not isinstance(answers, dict):
        answers = {}
    try:
        node_id = int(data.get('guide_node_id')) if data.get('guide_node_id') not in (None, '', 0) else None
    except (ValueError, TypeError):
        node_id = None

    public_user = _public_user_for_website(website)
    visitor_id, should_set_cookie = get_or_create_asset_visitor_id()
    visitor_hash = hash_asset_visitor_id(visitor_id)
    now = datetime.now(timezone.utc).replace(tzinfo=None)

    rec = QuizDraft.query.filter_by(quiz_id=quiz.id, visitor_id_hash=visitor_hash).first()
    if rec:
        rec.answers = answers
        rec.updated_at = now
        rec.guide_node_id = node_id
        if public_user and not rec.public_user_id:
            rec.public_user_id = public_user.id
    else:
        db.session.add(QuizDraft(
            quiz_id=quiz.id, website_id=website.id, guide_node_id=node_id,
            public_user_id=public_user.id if public_user else None,
            visitor_id_hash=visitor_hash, answers=answers, updated_at=now))
    db.session.commit()
    resp = _utf8_json({'success': True})
    return _set_visitor_cookie(resp, visitor_id) if should_set_cookie else resp


def _clear_quiz_draft(quiz_id, public_user, visitor_hash):
    """Drop saved drafts for this quiz + identity once it's submitted."""
    q = QuizDraft.query.filter(QuizDraft.quiz_id == quiz_id)
    if public_user:
        q = q.filter(db.or_(QuizDraft.public_user_id == public_user.id,
                            QuizDraft.visitor_id_hash == visitor_hash))
    else:
        q = q.filter(QuizDraft.visitor_id_hash == visitor_hash)
    q.delete(synchronize_session=False)


# Match `data-quiz-id="123"` (single or double quoted) in a lesson's HTML body.
_QUIZ_EMBED_RE = re.compile(r'''data-quiz-id=["'](\d+)["']''')


def _lesson_quiz_ids(node):
    """Return the list of quiz ids embedded in a lesson's body, in document
    order. Empty list when the lesson has no quiz embed."""
    if not node or not node.content:
        return []
    return [int(m) for m in _QUIZ_EMBED_RE.findall(node.content)]


def _quiz_passed(quiz, score, max_score):
    """True iff `score` clears this quiz's pass_threshold * max_score."""
    if not max_score:
        return False
    thresh = quiz.pass_threshold if quiz.pass_threshold is not None else 0.9
    return (score / max_score) >= thresh


# Result keys safe to return on a failing attempt: they convey right/wrong
# (and partial progress) without revealing the actual answers. Everything else
# (correct_option_ids, accepted, blank_accepted, correct_pairs, answer_order)
# is withheld until the reader passes.
_SAFE_RESULT_KEYS = {'question_id', 'correct', 'earned', 'blank_results',
                     # coding: the learner's own output/compiler errors and
                     # per-test pass flags are safe (their `tests_expected` is
                     # the revealing part and is dropped).
                     'tests', 'compile_output', 'runner_error', 'language', 'mode'}


def _strip_answers_from_results(results):
    """When a reader hasn't passed, keep only the non-revealing feedback (which
    questions/blanks were right, and partial credit earned) and drop anything
    that would disclose the correct answer."""
    return [{k: v for k, v in r.items() if k in _SAFE_RESULT_KEYS} for r in results]


def _mark_lesson_complete_if_passed(node, public_user, visitor_hash):
    """If `node` is a quiz-gated lesson and every embedded quiz has a passing
    best score for this identity, stamp completed_at on its GuideProgress row
    (creating the row if missing). Idempotent. Returns True iff just marked."""
    if not node or node.node_type != 'lesson':
        return False
    quiz_ids = _lesson_quiz_ids(node)
    if not quiz_ids:
        return False
    for qid in quiz_ids:
        quiz = Quiz.query.get(qid)
        if not quiz:
            return False  # missing quiz can't be passed
        questions = quiz.questions.all()
        max_score = sum(q.points for q in questions)
        if not max_score:
            return False
        best = _quiz_best_score(qid, public_user, visitor_hash)
        if not _quiz_passed(quiz, best, max_score):
            return False
    now = datetime.now(timezone.utc).replace(tzinfo=None)
    rec = GuideProgress.query.filter_by(guide_node_id=node.id,
                                        visitor_id_hash=visitor_hash).first()
    if rec:
        if rec.completed_at:
            return False
        rec.completed_at = now
        rec.last_viewed_at = now
        if public_user and not rec.public_user_id:
            rec.public_user_id = public_user.id
    else:
        db.session.add(GuideProgress(
            guide_id=node.guide_id, guide_node_id=node.id, website_id=node.website_id,
            visitor_id_hash=visitor_hash,
            public_user_id=public_user.id if public_user else None,
            first_viewed_at=now, last_viewed_at=now, completed_at=now))
    db.session.commit()
    return True


@app.route('/api/quizzes/<int:qid>/submit', methods=['POST'])
def public_quiz_submit(qid):
    quiz = Quiz.query.get_or_404(qid)
    website = _live_website_for(quiz)
    data = request.get_json() or {}
    submitted = data.get('answers') or {}
    try:
        node_id = int(data.get('guide_node_id')) if data.get('guide_node_id') not in (None, '', 0) else None
    except (ValueError, TypeError):
        node_id = None
    score, max_score, results = _grade_quiz(quiz, submitted)
    this_attempt_passed = _quiz_passed(quiz, score, max_score)

    public_user = _public_user_for_website(website)
    visitor_id, should_set_cookie = get_or_create_asset_visitor_id()
    visitor_hash = hash_asset_visitor_id(visitor_id)
    db.session.add(QuizAttempt(
        quiz_id=quiz.id, website_id=website.id, guide_node_id=node_id,
        public_user_id=public_user.id if public_user else None,
        visitor_id_hash=visitor_hash, score=score, max_score=max_score, answers=submitted))
    # The attempt is now the record of these answers — discard the in-progress
    # draft so a later visit starts fresh (or from a new draft).
    _clear_quiz_draft(quiz.id, public_user, visitor_hash)
    db.session.commit()

    # If this quiz is embedded in a lesson, see whether the lesson is now done.
    # Done = every embedded quiz has a passing best-score for this identity.
    progress_summary = None
    if node_id is not None:
        node = GuideNode.query.get(node_id)
        if node and node.node_type == 'lesson':
            _mark_lesson_complete_if_passed(node, public_user, visitor_hash)
            guide = Guide.query.get(node.guide_id)
            if guide and guide.track_progress:
                progress_summary = _guide_progress_summary(guide, public_user, visitor_hash)

    # On a failing attempt, hide which options/text were correct — only the
    # per-question right/wrong stays. (Best score may still be passing if the
    # reader previously cleared the bar.)
    visible_results = results if this_attempt_passed else _strip_answers_from_results(results)

    body = {'success': True, 'score': score, 'max_score': max_score,
            'results': visible_results,
            'best_score': _quiz_best_score(quiz.id, public_user, visitor_hash),
            'passed': this_attempt_passed,
            'pass_threshold': quiz.pass_threshold if quiz.pass_threshold is not None else 0.9}
    if progress_summary is not None:
        body['progress'] = progress_summary
    resp = _utf8_json(body)
    return _set_visitor_cookie(resp, visitor_id) if should_set_cookie else resp


def _guide_progress_summary(guide, public_user, visitor_hash):
    lessons = _guide_reading_order(guide)
    lesson_ids = {n.id for n in lessons}
    total = len(lesson_ids)
    q = GuideProgress.query.filter(GuideProgress.guide_id == guide.id,
                                   GuideProgress.completed_at.isnot(None))
    if public_user:
        q = q.filter(db.or_(GuideProgress.public_user_id == public_user.id,
                            GuideProgress.visitor_id_hash == visitor_hash))
    else:
        q = q.filter(GuideProgress.visitor_id_hash == visitor_hash)
    completed = {r.guide_node_id for r in q.all()} & lesson_ids
    return {'completed_node_ids': list(completed), 'total': total,
            'completed': len(completed),
            'percent': round(100 * len(completed) / total) if total else 0}


def _resolve_published_guide_or_404(gid):
    guide = Guide.query.get_or_404(gid)
    website = _live_website_for(guide)
    if guide.status != 'published':
        abort(404)
    return guide, website


@app.route('/api/guides/<int:gid>/nodes/<int:nid>/progress', methods=['POST'])
def public_guide_progress_mark(gid, nid):
    guide, website = _resolve_published_guide_or_404(gid)
    if not guide.track_progress:
        return _utf8_json({'success': True, 'tracking': False})
    node = GuideNode.query.filter_by(id=nid, guide_id=gid, is_published=True).first_or_404()
    public_user = _public_user_for_website(website)
    visitor_id, should_set_cookie = get_or_create_asset_visitor_id()
    visitor_hash = hash_asset_visitor_id(visitor_id)
    now = datetime.now(timezone.utc).replace(tzinfo=None)
    # Lessons with an embedded quiz only complete on a passing attempt — not
    # on open. Record the visit either way.
    quiz_gated = bool(_lesson_quiz_ids(node))
    rec = GuideProgress.query.filter_by(guide_node_id=nid, visitor_id_hash=visitor_hash).first()
    if rec:
        rec.last_viewed_at = now
        if not rec.completed_at and not quiz_gated:
            rec.completed_at = now
        if public_user and not rec.public_user_id:
            rec.public_user_id = public_user.id
    else:
        db.session.add(GuideProgress(
            guide_id=gid, guide_node_id=nid, website_id=website.id,
            visitor_id_hash=visitor_hash,
            public_user_id=public_user.id if public_user else None,
            first_viewed_at=now, last_viewed_at=now,
            completed_at=None if quiz_gated else now))
    db.session.commit()
    resp = _utf8_json({'success': True, 'tracking': True,
                       'lesson_requires_quiz': quiz_gated,
                       **_guide_progress_summary(guide, public_user, visitor_hash)})
    return _set_visitor_cookie(resp, visitor_id) if should_set_cookie else resp


@app.route('/api/guides/<int:gid>/progress')
def public_guide_progress_get(gid):
    guide, website = _resolve_published_guide_or_404(gid)
    if not guide.track_progress:
        return _utf8_json({'success': True, 'tracking': False})
    public_user = _public_user_for_website(website)
    visitor_id, should_set_cookie = get_or_create_asset_visitor_id()
    visitor_hash = hash_asset_visitor_id(visitor_id)
    resp = _utf8_json({'success': True, 'tracking': True,
                       **_guide_progress_summary(guide, public_user, visitor_hash)})
    return _set_visitor_cookie(resp, visitor_id) if should_set_cookie else resp


# ════════════════════════════════════════════════════════════════════════════
# Member directory + public profiles — logged-in public users browse each other
# ════════════════════════════════════════════════════════════════════════════

def _require_member_area(prefix):
    """Gate the member directory / profiles: site must be live with public
    accounts on, and the viewer must be a logged-in public user. Returns
    (website, viewer, None) on success or (None, None, response) to short-circuit."""
    website = get_live_website(url_prefix=prefix) if prefix else get_live_website()
    if not website:
        return None, None, (render_template('no_site_found.html'), 404)
    if not website.is_live:
        return None, None, (render_template('site_offline.html', website=website), 503)
    if not website_uses_public_accounts(website):
        return None, None, ('Member profiles are not available for this site.', 404)
    viewer = _public_user_for_website(website)
    if not viewer:
        kwargs = {'next': request.path}
        if website.url_prefix:
            kwargs['website_prefix'] = website.url_prefix
        return None, None, redirect(url_for('public_login', **kwargs))
    return website, viewer, None


def _members_base_url(website):
    return url_for('public_members', prefix=website.url_prefix or None)


def _member_profile_url(website, user_id):
    return url_for('public_member_profile', user_id=user_id, prefix=website.url_prefix or None)


def _can_view_member_profile(viewer, target):
    """A profile is viewable when it's opted-in, or the viewer is the owner or
    a staff/admin mirror (so moderators can always look)."""
    if target.profile_visible:
        return True
    if viewer and viewer.id == target.id:
        return True
    return bool(viewer and viewer.is_admin_mirror)


def _member_forum_activity(target_user, website, q=None, limit=100):
    """Combined list of a user's forum threads + replies (newest first),
    optionally filtered by a search string. Hidden content is excluded."""
    like = f'%{q.strip()}%' if (q and q.strip()) else None
    tq = ForumThread.query.filter(ForumThread.website_id == website.id,
                                  ForumThread.public_user_id == target_user.id,
                                  ForumThread.is_hidden == False)
    rq = ForumReply.query.join(ForumThread, ForumReply.thread_id == ForumThread.id).filter(
        ForumReply.website_id == website.id,
        ForumReply.public_user_id == target_user.id,
        ForumReply.is_hidden == False,
        ForumThread.is_hidden == False)
    if like:
        tq = tq.filter(db.or_(ForumThread.title.ilike(like), ForumThread.body.ilike(like)))
        rq = rq.filter(ForumReply.body.ilike(like))
    items = []
    for t in tq.order_by(ForumThread.created_at.desc()).limit(limit).all():
        items.append({'kind': 'thread', 'thread_id': t.id, 'title': t.title,
                      'body': t.body, 'created_at': t.created_at,
                      'votes': t.vote_count_cached or 0, 'replies': t.reply_count or 0})
    for r in rq.order_by(ForumReply.created_at.desc()).limit(limit).all():
        items.append({'kind': 'reply', 'thread_id': r.thread_id,
                      'title': r.thread.title if r.thread else '(deleted thread)',
                      'body': r.body, 'created_at': r.created_at,
                      'votes': r.vote_count_cached or 0, 'replies': 0})
    items.sort(key=lambda x: x['created_at'] or datetime.min, reverse=True)
    return items[:limit]


def _member_guide_progress(target_user, website):
    """Every published guide this user has made progress on, with per-guide
    completed/total counts. Completed guides sort first."""
    rows = GuideProgress.query.filter(GuideProgress.website_id == website.id,
                                      GuideProgress.public_user_id == target_user.id).all()
    by_guide = {}
    for r in rows:
        slot = by_guide.setdefault(r.guide_id, {'viewed': set(), 'completed': set()})
        slot['viewed'].add(r.guide_node_id)
        if r.completed_at:
            slot['completed'].add(r.guide_node_id)
    out = []
    for gid, data in by_guide.items():
        guide = Guide.query.get(gid)
        if not guide or guide.website_id != website.id or guide.status != 'published':
            continue
        lesson_ids = {n.id for n in _guide_reading_order(guide)}
        if not (data['viewed'] & lesson_ids):
            continue
        total = len(lesson_ids)
        completed = len(data['completed'] & lesson_ids)
        out.append({'guide': guide, 'total': total, 'completed': completed,
                    'percent': round(100 * completed / total) if total else 0,
                    'is_done': total > 0 and completed >= total})
    out.sort(key=lambda x: (not x['is_done'], -x['percent'], x['guide'].title.lower()))
    return out


_KSA_PRIO_NAMES = ['core', 'high', 'medium', 'low']


def _ksa_user_completions(user, website):
    """Precompute, for one member, the sets used to mark KSA resources done:
    completed guide ids, passed quiz ids, and manually-completed resource ids
    (links the member ticked + demonstrations an admin signed off)."""
    if not user:
        return (set(), set(), set())
    done_guides = {g['guide'].id for g in _member_guide_progress(user, website) if g['is_done']}
    best = {}
    for a in QuizAttempt.query.filter_by(public_user_id=user.id).all():
        if a.max_score and a.max_score > 0:
            frac = a.score / a.max_score
            if frac > best.get(a.quiz_id, -1.0):
                best[a.quiz_id] = frac
    passed = set()
    if best:
        for q in Quiz.query.filter(Quiz.id.in_(list(best.keys()))).all():
            if best.get(q.id, 0) >= (q.pass_threshold or 0):
                passed.add(q.id)
    done_resources = {c.resource_id for c in
                      KSAResourceCompletion.query.filter_by(public_user_id=user.id).all()}
    return (done_guides, passed, done_resources)


def _ksa_dev_resources(ksa, website, guide_cache=None, quiz_cache=None, completions=None):
    """The learning resources attached to a KSA (links / published guides /
    quizzes / demonstrations), resolved to public URLs for this website, each
    annotated with whether the viewing member has completed it. `completions` is
    the tuple from _ksa_user_completions. Optional caches avoid re-fetching the
    same guide/quiz across many KSAs."""
    guide_cache = guide_cache if guide_cache is not None else {}
    quiz_cache = quiz_cache if quiz_cache is not None else {}
    done_guides, passed_quizzes, done_resources = completions or (set(), set(), set())
    items = []
    for rs in ksa.resources.order_by(KSAResource.sort_order, KSAResource.id).all():
        if rs.resource_type == 'link' and rs.url:
            items.append({'type': 'link', 'label': rs.label or rs.url, 'url': rs.url,
                          'resource_id': rs.id, 'manual': True,
                          'completed': rs.id in done_resources})
        elif rs.resource_type == 'guide' and rs.guide_id:
            g = guide_cache.get(rs.guide_id)
            if g is None:
                g = db.session.get(Guide, rs.guide_id)
                guide_cache[rs.guide_id] = g
            if g and g.website_id == website.id and g.status == 'published':
                gurl = (('/' + website.url_prefix + '/guides/' + g.slug)
                        if website.url_prefix else ('/guides/' + g.slug))
                items.append({'type': 'guide', 'label': rs.label or g.title, 'url': gurl,
                              'resource_id': rs.id, 'completed': g.id in done_guides})
        elif rs.resource_type == 'quiz' and rs.quiz_id:
            qz = quiz_cache.get(rs.quiz_id)
            if qz is None:
                qz = db.session.get(Quiz, rs.quiz_id)
                quiz_cache[rs.quiz_id] = qz
            if qz and qz.website_id == website.id:
                items.append({'type': 'quiz', 'label': rs.label or qz.title,
                              'url': url_for('public_quiz_page', qid=qz.id),
                              'resource_id': rs.id, 'completed': qz.id in passed_quizzes})
        elif rs.resource_type == 'demo':
            items.append({'type': 'demo', 'label': rs.label or 'Demonstration',
                          'url': None, 'resource_id': rs.id,
                          'description': rs.description or '',
                          'completed': rs.id in done_resources})
    return items


def _browse_all_skills(website, viewer, group_by_folder=False):
    """A self-development catalog of EVERY KSA on the website, grouped by its
    owning division, annotated with the viewer's current level and the learning
    resources attached to each — so a member can pick up any skill, even ones
    outside their own divisions/roles. group_by_folder=False → a single flat
    list per division (no folder headers); True → grouped by folder."""
    ksas = KSA.query.filter_by(website_id=website.id).all()
    if not ksas:
        return []
    divisions = {d.id: d for d in Division.query.filter_by(website_id=website.id).all()}
    recs = {uk.ksa_id: uk for uk in UserKSA.query.filter(
        UserKSA.public_user_id == viewer.id,
        UserKSA.ksa_id.in_([k.id for k in ksas])).all()}
    gc, qc = {}, {}
    comp = _ksa_user_completions(viewer, website)
    folders_by_div = {}
    for f in KSAFolder.query.filter_by(website_id=website.id).all():
        folders_by_div.setdefault(f.division_id, []).append(f)
    by_div = {}
    for k in ksas:
        by_div.setdefault(k.division_id, []).append(k)

    def _mk(k):
        uk = recs.get(k.id)
        lv = uk.level if uk else 0
        return {
            'id': k.id, 'name': k.name, 'type': k.ksa_type, 'level': lv,
            'description': k.description or '',
            'label': _ksa_level_label(website, lv), 'max': k.max_level,
            # verified = an admin set it (read-only); self_reported = member set it.
            'verified': bool(uk and lv > 0 and not uk.self_reported),
            'self_reported': bool(uk and uk.self_reported),
            'resources': _ksa_dev_resources(k, website, gc, qc, comp),
        }
    _name_key = lambda x: ((x.ksa_type or ''), (x.name or '').lower())

    out = []
    for d in sorted(divisions.values(), key=lambda x: (x.sort_order, (x.name or '').lower())):
        klist = by_div.get(d.id)
        if not klist:
            continue
        folders = sorted(folders_by_div.get(d.id, []),
                         key=lambda f: (f.sort_order, (f.name or '').lower()))
        valid = {f.id for f in folders}
        kbf = {}
        for k in klist:
            kbf.setdefault(k.folder_id, []).append(k)
        groups = []
        for f in folders:
            if kbf.get(f.id):
                groups.append({'name': f.name, 'items': [_mk(k) for k in sorted(kbf[f.id], key=_name_key)]})
        unfiled = []
        for fid, kl in kbf.items():
            if fid is None or fid not in valid:
                unfiled.extend(kl)
        if unfiled:
            groups.append({'name': None, 'items': [_mk(k) for k in sorted(unfiled, key=_name_key)]})
        if not group_by_folder:
            flat = [it for g in groups for it in g['items']]
            flat.sort(key=lambda x: ((x['type'] or ''), (x['name'] or '').lower()))
            groups = [{'name': None, 'items': flat}] if flat else []
        out.append({'division': d, 'ksa_groups': groups})
    return out


def _member_ksa_profile(target_user, website, full=False, group_by_folder=False):
    """A member's competency view, grouped by division.

    group_by_folder=False (default) → each division is one flat list, gap/priority
    sorted (the "hopper" view). True → KSAs grouped under their folder headers.

    full=False (others' profiles) → an attainment *showcase*: only KSAs the
    member holds (level >= 1), no targets/resources.

    full=True (own profile) → the learning *roadmap*: every KSA in the member's
    divisions including not-yet-started ones, annotated with the target level /
    priority / required-vs-recommended derived from the roles they hold, plus
    the learning resources attached to each KSA. Unmet required gaps sort first.
    """
    out = []
    memberships = DivisionMembership.query.filter_by(public_user_id=target_user.id).all()
    target_roles = target_user.roles or []
    _guide_cache, _quiz_cache = {}, {}
    _completions = _ksa_user_completions(target_user, website) if full else None

    def _resources_for(ksa):
        return _ksa_dev_resources(ksa, website, _guide_cache, _quiz_cache, _completions)

    for m in memberships:
        d = db.session.get(Division, m.division_id)
        if not d or d.website_id != website.id:
            continue
        roles = [r for r in target_roles if r.division_id == d.id]
        # Aggregate this member's requirements per KSA across their division roles.
        req_map = {}
        if full:
            for r in roles:
                for rk in r.ksa_requirements.all():
                    slot = req_map.setdefault(rk.ksa_id, {'level': 0, 'required': False,
                                                          'prank': 3, '_role_ids': set(), 'roles': []})
                    slot['level'] = max(slot['level'], rk.required_level)
                    slot['required'] = slot['required'] or rk.required
                    slot['prank'] = min(slot['prank'], {'core': 0, 'high': 1, 'medium': 2, 'low': 3}.get(rk.priority, 2))
                    # Remember which of the member's roles require this KSA so the
                    # profile can show role attribution and filter by role.
                    if r.id not in slot['_role_ids']:
                        slot['_role_ids'].add(r.id)
                        slot['roles'].append({'id': r.id, 'name': r.name, 'color': r.color})
        fgroups = _division_ksa_folder_groups(d.id)
        ksas = [k for g in fgroups for k in g['ksas']]
        levels = {}
        if ksas:
            for uk in UserKSA.query.filter(UserKSA.public_user_id == target_user.id,
                                           UserKSA.ksa_id.in_([k.id for k in ksas])).all():
                levels[uk.ksa_id] = uk.level

        def _mk_item(k):
            lv = levels.get(k.id, 0)
            if not full and lv < 1:
                return None
            req = req_map.get(k.id) if full else None
            target = req['level'] if req else 0
            return {
                'id': k.id, 'name': k.name, 'type': k.ksa_type, 'level': lv,
                'description': k.description or '',
                'label': _ksa_level_label(website, lv), 'max': k.max_level,
                'target': target,
                'target_label': _ksa_level_label(website, target) if target else None,
                'required': (req['required'] if req else None),
                'priority': (_KSA_PRIO_NAMES[req['prank']] if req else None),
                'met': (target == 0) or (lv >= target),
                'resources': _resources_for(k) if full else [],
                'roles': (req['roles'] if req else []),
            }

        def _sort_items(items):
            if full:
                items.sort(key=lambda x: (
                    0 if (x['target'] and not x['met']) else (1 if x['target'] else 2),
                    {'core': 0, 'high': 1, 'medium': 2, 'low': 3}.get(x['priority'], 4),
                    x['name'].lower()))
            return items

        # Group the division's KSAs by their folder so the roadmap mirrors the
        # admin's folder organisation. Empty folders (after the level≥1 filter in
        # showcase mode) are dropped.
        ksa_groups = []
        for g in fgroups:
            g_items = [it for it in (_mk_item(k) for k in g['ksas']) if it is not None]
            if g_items:
                ksa_groups.append({'name': g['name'], 'items': _sort_items(g_items)})
        if not group_by_folder:
            # Flat "hopper" view: one unnamed group, gap/priority sorted across
            # all folders (renders without folder headers — the old default).
            flat = [it for grp in ksa_groups for it in grp['items']]
            ksa_groups = [{'name': None, 'items': _sort_items(flat)}] if flat else []
        out.append({'division': d, 'status': m.status,
                    'roles': [{'id': r.id, 'name': r.name, 'color': r.color} for r in roles],
                    'ksa_groups': ksa_groups})
    out.sort(key=lambda x: (x['status'] != 'active', (x['division'].name or '').lower()))
    return out


def _member_other_skills(target_user, website, full=False):
    """Self-reported skills the member holds (level≥1) that fall OUTSIDE their
    divisions — surfaced as an 'Other skills' group so self-declared cross-division
    skills are visible on the profile and not duplicated with the division groups."""
    my_div_ids = {m.division_id for m in
                  DivisionMembership.query.filter_by(public_user_id=target_user.id).all()}
    rows = (UserKSA.query.filter_by(public_user_id=target_user.id, self_reported=True)
            .filter(UserKSA.level >= 1).all())
    if not rows:
        return []
    gc, qc = {}, {}
    comp = _ksa_user_completions(target_user, website) if full else None
    items = []
    for uk in rows:
        k = db.session.get(KSA, uk.ksa_id)
        if not k or k.website_id != website.id or k.division_id in my_div_ids:
            continue
        items.append({
            'id': k.id, 'name': k.name, 'type': k.ksa_type, 'level': uk.level,
            'description': k.description or '',
            'label': _ksa_level_label(website, uk.level), 'max': k.max_level,
            'resources': _ksa_dev_resources(k, website, gc, qc, comp) if full else [],
        })
    items.sort(key=lambda x: ((x['type'] or ''), x['name'].lower()))
    return items


@app.route('/members', defaults={'prefix': None})
@app.route('/<string:prefix>/members')
def public_members(prefix=None):
    return _render_members_directory(prefix)


def _render_members_directory(prefix):
    website, viewer, short = _require_member_area(prefix)
    if short is not None:
        return short
    q = (request.args.get('q') or '').strip()
    # Role filter: chips on the page link to ?role=<id>. Only this website's
    # roles are valid; an unknown id falls back to "all".
    roles = (PublicUserRole.query.filter_by(website_id=website.id)
             .order_by(db.func.lower(PublicUserRole.name)).all())
    role_id = request.args.get('role', type=int)
    active_role = next((r for r in roles if r.id == role_id), None)
    # A role name can exist in several divisions; collapse the filter chips to one
    # per NAME (filtering then matches members holding that role in ANY division),
    # so the same name no longer appears multiple times. A name chip is "archived"
    # only when every role sharing that name is excluded from the directory.
    _by_name = {}
    for r in roles:
        key = (r.name or '').lower()
        slot = _by_name.get(key)
        if slot is None:
            slot = {'id': r.id, 'name': r.name, 'color': r.color, 'exclude': True}
            _by_name[key] = slot
        if not r.exclude_from_directory:
            slot['exclude'] = False
    role_filters = list(_by_name.values())
    # Division filter: chips link to ?division=<id> (members of that division).
    divisions = (Division.query.filter_by(website_id=website.id)
                 .order_by(Division.sort_order, Division.name).all())
    division_id = request.args.get('division', type=int)
    active_division = next((d for d in divisions if d.id == division_id), None)
    # Skill filter: find members who hold a given KSA at >= a chosen level.
    # Skills are grouped by their owning division for the dropdown.
    all_ksas = KSA.query.filter_by(website_id=website.id).order_by(KSA.name).all()
    skill_id = request.args.get('ksa', type=int)
    active_skill = next((k for k in all_ksas if k.id == skill_id), None)
    skill_level = request.args.get('level', type=int) or 1
    # Clamp to the configured level range so the template's level_labels[...]
    # lookup is always in bounds (a crafted ?level=99 can't break the page).
    _max_lvl = len(_ksa_level_labels(website)) - 1
    skill_level = max(1, min(skill_level, max(1, _max_lvl)))
    # Verified-only: restrict the skill match to admin-verified levels (excludes
    # members who only self-reported the skill).
    skill_verified = str(request.args.get('verified', '')).lower() in ('1', 'true', 'on')
    _ks_by_div = {}
    for k in all_ksas:
        _ks_by_div.setdefault(k.division_id, []).append(k)
    skill_groups = [{'division': d.name, 'ksas': _ks_by_div[d.id]}
                    for d in divisions if d.id in _ks_by_div]

    query = PublicUser.query.filter(PublicUser.website_id == website.id,
                                    PublicUser.is_banned == False,
                                    PublicUser.is_active_public == True,
                                    PublicUser.profile_visible == True)
    if q:
        like = f'%{q}%'
        query = query.filter(db.or_(
            PublicUser.display_username.ilike(like),
            PublicUser.username.ilike(like),
            PublicUser.first_name.ilike(like),
            PublicUser.last_name.ilike(like)))
    if active_role is not None:
        # Match by NAME so the chip covers that role across all divisions.
        query = query.filter(PublicUser.roles.any(db.and_(
            PublicUserRole.website_id == website.id,
            db.func.lower(PublicUserRole.name) == (active_role.name or '').lower())))
    if active_division is not None:
        query = query.filter(PublicUser.division_memberships.any(
            DivisionMembership.division_id == active_division.id))
    if active_skill is not None:
        _skill_conds = [UserKSA.ksa_id == active_skill.id, UserKSA.level >= skill_level]
        if skill_verified:
            _skill_conds.append(UserKSA.self_reported == False)
        query = query.filter(PublicUser.ksa_levels.any(db.and_(*_skill_conds)))
    # "Excluded" roles (e.g. Alumni) drop their members from the default and
    # any normal-role view, but are still browsable by selecting that role.
    exclude_role_ids = [r.id for r in roles if r.exclude_from_directory]
    if exclude_role_ids and (active_role is None or not active_role.exclude_from_directory):
        query = query.filter(~PublicUser.roles.any(PublicUserRole.id.in_(exclude_role_ids)))
    query = query.order_by(db.func.lower(db.func.coalesce(
        PublicUser.display_username, PublicUser.username)).asc())
    page = request.args.get('page', 1, type=int)
    pagination = query.paginate(page=page, per_page=30, error_out=False)
    # Division badges per member on the page (batched), each carrying the roles
    # that member holds within that division so division-scoped roles render
    # encapsulated under their division (matching the profile page).
    member_divisions = {}
    _mids = [u.id for u in pagination.items]
    _user_by_id = {u.id: u for u in pagination.items}
    if _mids:
        _dc = {}
        for ms in DivisionMembership.query.filter(DivisionMembership.public_user_id.in_(_mids)).all():
            d = _dc.get(ms.division_id)
            if d is None:
                d = db.session.get(Division, ms.division_id)
                _dc[ms.division_id] = d
            if d and d.website_id == website.id:
                u = _user_by_id.get(ms.public_user_id)
                d_roles = [r for r in (u.roles or []) if r.division_id == d.id] if u else []
                member_divisions.setdefault(ms.public_user_id, []).append(
                    {'name': d.name, 'color': d.color or '#5eeef8',
                     'icon': d.icon or '', 'status': ms.status,
                     'roles': [{'name': r.name, 'color': r.color} for r in d_roles]})
    # Each shown member's level for the active skill (for a badge on the card),
    # plus whether that level is self-reported (vs admin-verified).
    member_skill_levels = {}
    member_skill_selfreported = {}
    if active_skill is not None and _mids:
        for uk in UserKSA.query.filter(UserKSA.public_user_id.in_(_mids),
                                       UserKSA.ksa_id == active_skill.id).all():
            member_skill_levels[uk.public_user_id] = uk.level
            member_skill_selfreported[uk.public_user_id] = bool(uk.self_reported)
    return render_template('public_members.html', website=website, public_user=viewer,
                           members=pagination.items, pagination=pagination, q=q,
                           roles=roles, role_filters=role_filters, active_role=active_role,
                           divisions=divisions, active_division=active_division,
                           member_divisions=member_divisions,
                           skill_groups=skill_groups, active_skill=active_skill,
                           skill_level=skill_level, skill_verified=skill_verified,
                           member_skill_levels=member_skill_levels,
                           member_skill_selfreported=member_skill_selfreported,
                           level_labels=_ksa_level_labels(website),
                           members_base=_members_base_url(website),
                           members_filter_url=lambda **kw: url_for(
                               'public_members', prefix=website.url_prefix or None, **kw),
                           profile_url=lambda u: _member_profile_url(website, u))


@app.route('/members/<int:user_id>', defaults={'prefix': None})
@app.route('/<string:prefix>/members/<int:user_id>')
def public_member_profile(user_id, prefix=None):
    return _render_member_profile(prefix, user_id)


@app.route('/skills/<int:ksa_id>/level', defaults={'prefix': None}, methods=['POST'])
@app.route('/<string:prefix>/skills/<int:ksa_id>/level', methods=['POST'])
def public_set_own_skill_level(ksa_id, prefix=None):
    """A member self-reports their own level on ANY skill on the site (even one
    outside their divisions/roles) so they can track skills they're developing
    and be found in the directory skill filter. Self-reported levels are flagged
    and never overwrite an admin-verified level."""
    website, viewer, short = _require_member_area(prefix)
    if short is not None:
        return short
    ksa = KSA.query.filter_by(id=ksa_id, website_id=website.id).first()
    if not ksa:
        return _utf8_json({'success': False, 'error': 'Skill not found.'}, 404)
    try:
        level = int((request.get_json(silent=True) or {}).get('level'))
    except (TypeError, ValueError):
        return _utf8_json({'success': False, 'error': 'Invalid level.'}, 400)
    level = max(0, min(level, ksa.max_level))

    rec = UserKSA.query.filter_by(public_user_id=viewer.id, ksa_id=ksa_id).first()
    # An admin-verified level is owned by staff — members can't change it here.
    if rec and not rec.self_reported:
        return _utf8_json({'success': False, 'verified': True,
                           'error': 'This level was verified by an admin and can only be changed by staff.'}, 403)

    now = datetime.now(timezone.utc).replace(tzinfo=None)
    if level == 0:
        if rec:
            db.session.delete(rec)
    elif rec:
        rec.level = level
        rec.updated_at = now
        rec.self_reported = True
    else:
        db.session.add(UserKSA(public_user_id=viewer.id, ksa_id=ksa_id, level=level,
                               self_reported=True, granted_at=now))
    db.session.commit()
    return _utf8_json({'success': True, 'level': level,
                       'label': _ksa_level_label(website, level)})


@app.route('/skills/resource/<int:rid>/toggle', defaults={'prefix': None}, methods=['POST'])
@app.route('/<string:prefix>/skills/resource/<int:rid>/toggle', methods=['POST'])
def public_toggle_resource_complete(rid, prefix=None):
    """A member ticks a 'link' learning resource done (guides/quizzes auto-track
    from progress; demonstrations are admin-signed-off — neither is togglable here)."""
    website, viewer, short = _require_member_area(prefix)
    if short is not None:
        return short
    rs = db.session.get(KSAResource, rid)
    if not rs or rs.resource_type != 'link':
        return _utf8_json({'success': False, 'error': 'This resource cannot be marked here.'}, 400)
    k = db.session.get(KSA, rs.ksa_id)
    if not k or k.website_id != website.id:
        return _utf8_json({'success': False, 'error': 'Resource not found.'}, 404)
    rec = KSAResourceCompletion.query.filter_by(public_user_id=viewer.id, resource_id=rid).first()
    if rec:
        db.session.delete(rec)
        db.session.commit()
        return _utf8_json({'success': True, 'completed': False})
    db.session.add(KSAResourceCompletion(public_user_id=viewer.id, resource_id=rid))
    db.session.commit()
    return _utf8_json({'success': True, 'completed': True})


def _render_member_profile(prefix, user_id):
    website, viewer, short = _require_member_area(prefix)
    if short is not None:
        return short
    target = PublicUser.query.filter_by(id=user_id, website_id=website.id).first()
    if not target or target.is_banned or not target.is_active_public:
        abort(404)
    if not _can_view_member_profile(viewer, target):
        abort(404)

    tab = request.args.get('tab', 'forum')
    if tab not in ('forum', 'guides', 'roles', 'ksas', 'explore'):
        tab = 'forum'
    q = (request.args.get('q') or '').strip()
    # Competency layout: 'priority' (flat hopper, default) or 'categories' (folders).
    ksa_view = 'categories' if request.args.get('ksaview') == 'categories' else 'priority'
    _by_folder = (ksa_view == 'categories')

    thread_count = ForumThread.query.filter_by(website_id=website.id,
        public_user_id=target.id, is_hidden=False).count()
    reply_count = ForumReply.query.filter_by(website_id=website.id,
        public_user_id=target.id, is_hidden=False).count()

    is_self = (viewer.id == target.id)
    forum_items = _member_forum_activity(target, website, q) if tab == 'forum' else None
    guide_items = _member_guide_progress(target, website) if tab == 'guides' else None
    ksa_profile = _member_ksa_profile(target, website, full=is_self, group_by_folder=_by_folder) if tab == 'ksas' else None
    other_skills = _member_other_skills(target, website, full=is_self) if tab == 'ksas' else None
    # "Explore" is a self-only catalog of every KSA on the site (any division).
    all_skills = _browse_all_skills(website, viewer, group_by_folder=_by_folder) if (tab == 'explore' and is_self) else None
    # Cheap counts for the tab labels (computed regardless of active tab).
    guides_done = sum(1 for g in _member_guide_progress(target, website) if g['is_done'])
    division_count = DivisionMembership.query.filter_by(public_user_id=target.id).count()
    # Show the Competencies tab if the member is in a division OR has self-declared
    # skills outside any division (so non-members with skills still surface them).
    self_skill_count = (UserKSA.query.filter_by(public_user_id=target.id, self_reported=True)
                        .filter(UserKSA.level >= 1).count())
    show_ksa_tab = bool(division_count or self_skill_count)
    all_skills_count = KSA.query.filter_by(website_id=website.id).count() if is_self else 0

    # Split roles: site-wide vs division-scoped, and group the latter under
    # their division so the profile shows which divisions the member holds
    # roles in (especially when they span several divisions).
    _all_roles = target.roles or []
    site_roles = [r for r in _all_roles if r.division_id is None]
    _roles_by_div = {}
    for r in _all_roles:
        if r.division_id:
            _roles_by_div.setdefault(r.division_id, []).append(r)
    division_role_groups = []
    if _roles_by_div:
        _divs = Division.query.filter(Division.id.in_(_roles_by_div.keys()),
                                      Division.website_id == website.id).all()
        for d in sorted(_divs, key=lambda x: (x.sort_order, (x.name or '').lower())):
            division_role_groups.append({'division': d, 'roles': _roles_by_div[d.id]})

    def _forum_thread_url(thread_id):
        return (url_for('public_forum_thread', thread_id=thread_id, prefix=website.url_prefix)
                if website.url_prefix else url_for('public_forum_thread', thread_id=thread_id))

    def _division_member_url(division_id):
        return url_for('public_members', prefix=website.url_prefix or None, division=division_id)

    return render_template('public_member_profile.html', website=website, public_user=viewer,
                           target=target, tab=tab, q=q,
                           thread_count=thread_count, reply_count=reply_count,
                           post_count=thread_count + reply_count, guides_done=guides_done,
                           forum_items=forum_items, guide_items=guide_items,
                           ksa_profile=ksa_profile, division_count=division_count,
                           other_skills=other_skills, show_ksa_tab=show_ksa_tab,
                           ksa_view=ksa_view,
                           all_skills=all_skills, all_skills_count=all_skills_count,
                           ksa_level_labels=(_ksa_level_labels(website) if is_self else None),
                           skill_level_base=(('/' + website.url_prefix + '/skills/')
                                             if website.url_prefix else '/skills/'),
                           resource_toggle_base=(('/' + website.url_prefix + '/skills/resource/')
                                                 if website.url_prefix else '/skills/resource/'),
                           site_roles=site_roles, division_role_groups=division_role_groups,
                           ksa_full=is_self,
                           is_self=is_self,
                           members_base=_members_base_url(website),
                           forum_thread_url=_forum_thread_url,
                           division_member_url=_division_member_url,
                           profile_base=_member_profile_url(website, target.id))


@app.route('/admin/settings/profanity', methods=['POST'])
@login_required
@require_perm('posts.settings')
def save_profanity_settings():
    data = request.get_json() or {}
    enabled = bool(data.get('enabled', False))
    words   = (data.get('words') or '').strip() or None
    action  = data.get('action', 'block') if data.get('action') in ('block', 'replace') else 'block'
    live_websites = Website.query.filter_by(user_id=current_user.root_user_id, is_draft=False).all()
    if not live_websites:
        return _utf8_json({'error': 'No website'}, 400)
    for w in live_websites:
        w.profanity_filter_enabled = enabled
        w.post_profanity_words     = words
        w.post_profanity_action    = action
    db.session.commit()
    return _utf8_json({'success': True})


# ════════════════════════════════════════════════════════════════════════════
# Storage Connections — external drives (Google Drive, OneDrive, …)
# ════════════════════════════════════════════════════════════════════════════

STORAGE_PROVIDERS = ('google_drive', 'onedrive', 'webdav', 's3', 'local_path', 'smb')

# Where the OAuth provider should redirect the user after they grant access.
# Uses _external=True so it includes scheme + host. Each provider has its own
# callback route below.


def _storage_now():
    return datetime.now(timezone.utc).replace(tzinfo=None)


def _storage_get_app_credentials(provider):
    return OAuthAppCredentials.query.filter_by(provider=provider).first()


def _storage_set_token(connection, access_token, refresh_token=None,
                       expires_in=None, scope=None):
    """Persist (encrypted) OAuth tokens onto a connection's config."""
    cfg = dict(connection.config or {})
    if access_token is not None:
        cfg['access_token'] = encrypt_api_key(access_token)
    if refresh_token:
        cfg['refresh_token'] = encrypt_api_key(refresh_token)
    if expires_in is not None:
        cfg['token_expires_at'] = (_storage_now() + timedelta(seconds=int(expires_in) - 60)).isoformat()
    if scope:
        cfg['scope'] = scope
    connection.config = cfg


def _storage_get_token(connection):
    cfg = connection.config or {}
    return decrypt_api_key(cfg.get('access_token') or '')


def _storage_token_expired(connection):
    cfg = connection.config or {}
    ts = cfg.get('token_expires_at')
    if not ts:
        return True
    try:
        return _storage_now() >= datetime.fromisoformat(ts)
    except Exception:
        return True


class StorageAdapter:
    """Base class for external storage providers.

    Subclasses must implement:
      - test(connection) -> (ok: bool, message: str)
      - list_folder(connection, folder_id=None) -> list[dict]
            Each dict has: id, name, type ('folder'|'file'), size, mime_type,
            modified, icon_url (optional), thumbnail_url (optional),
            export_mime (optional, for provider-side conversion targets).
      - download_file(connection, file_id, export_mime=None) -> (bytes, filename, mime_type)
    """
    provider_key = ''
    display_name = ''
    auth_kind = 'oauth'  # 'oauth' or 'credentials'

    def test(self, connection):  # pragma: no cover
        raise NotImplementedError

    def list_folder(self, connection, folder_id=None):  # pragma: no cover
        raise NotImplementedError

    def download_file(self, connection, file_id, export_mime=None):  # pragma: no cover
        raise NotImplementedError


# ── Google Drive ────────────────────────────────────────────────────────────

GOOGLE_DRIVE_SCOPE = 'https://www.googleapis.com/auth/drive.readonly'
GOOGLE_AUTH_URL = 'https://accounts.google.com/o/oauth2/v2/auth'
GOOGLE_TOKEN_URL = 'https://oauth2.googleapis.com/token'
GOOGLE_API_BASE = 'https://www.googleapis.com/drive/v3'

# Google Docs/Sheets/Slides aren't real files — they get exported on download.
GOOGLE_EXPORT_MAP = {
    'application/vnd.google-apps.document':     ('docx', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'),
    'application/vnd.google-apps.spreadsheet':  ('xlsx', 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'),
    'application/vnd.google-apps.presentation': ('pptx', 'application/vnd.openxmlformats-officedocument.presentationml.presentation'),
    'application/vnd.google-apps.drawing':      ('png',  'image/png'),
}


class GoogleDriveAdapter(StorageAdapter):
    provider_key = 'google_drive'
    display_name = 'Google Drive'
    auth_kind = 'oauth'

    @staticmethod
    def build_authorize_url(client_id, redirect_uri, state):
        from urllib.parse import urlencode
        params = {
            'client_id': client_id,
            'redirect_uri': redirect_uri,
            'response_type': 'code',
            'scope': GOOGLE_DRIVE_SCOPE,
            'access_type': 'offline',
            'include_granted_scopes': 'true',
            'prompt': 'consent',  # ensure we get a refresh_token
            'state': state,
        }
        return f'{GOOGLE_AUTH_URL}?{urlencode(params)}'

    @staticmethod
    def exchange_code(client_id, client_secret, code, redirect_uri):
        import requests as _req
        r = _req.post(GOOGLE_TOKEN_URL, data={
            'code': code,
            'client_id': client_id,
            'client_secret': client_secret,
            'redirect_uri': redirect_uri,
            'grant_type': 'authorization_code',
        }, timeout=20)
        r.raise_for_status()
        return r.json()

    @staticmethod
    def refresh_token(client_id, client_secret, refresh_token):
        import requests as _req
        r = _req.post(GOOGLE_TOKEN_URL, data={
            'client_id': client_id,
            'client_secret': client_secret,
            'refresh_token': refresh_token,
            'grant_type': 'refresh_token',
        }, timeout=20)
        r.raise_for_status()
        return r.json()

    def _ensure_token(self, connection):
        """Refresh the access token if expired. Returns a valid access token."""
        if not _storage_token_expired(connection):
            return _storage_get_token(connection)

        creds = _storage_get_app_credentials('google_drive')
        if not creds:
            raise RuntimeError('Google OAuth app credentials not configured.')
        client_secret_plain = decrypt_api_key(creds.client_secret)
        cfg = connection.config or {}
        refresh_plain = decrypt_api_key(cfg.get('refresh_token') or '')
        if not refresh_plain:
            raise RuntimeError('No refresh token available — reconnect this drive.')

        data = GoogleDriveAdapter.refresh_token(creds.client_id, client_secret_plain, refresh_plain)
        _storage_set_token(connection, data.get('access_token'),
                           expires_in=data.get('expires_in'))
        db.session.commit()
        return _storage_get_token(connection)

    def _api_get(self, connection, path, params=None, stream=False):
        import requests as _req
        token = self._ensure_token(connection)
        headers = {'Authorization': f'Bearer {token}'}
        r = _req.get(GOOGLE_API_BASE + path, headers=headers, params=params,
                     stream=stream, timeout=60)
        if r.status_code == 401:
            # Token may have just expired during the request; force a refresh and retry once.
            connection.config = {**(connection.config or {}),
                                 'token_expires_at': '1970-01-01T00:00:00'}
            db.session.commit()
            token = self._ensure_token(connection)
            headers['Authorization'] = f'Bearer {token}'
            r = _req.get(GOOGLE_API_BASE + path, headers=headers, params=params,
                         stream=stream, timeout=60)
        r.raise_for_status()
        return r

    def test(self, connection):
        try:
            r = self._api_get(connection, '/about', params={'fields': 'user(emailAddress,displayName)'})
            info = r.json().get('user', {})
            return True, f"Connected as {info.get('emailAddress') or info.get('displayName') or 'unknown'}"
        except Exception as e:
            return False, str(e)

    def list_folder(self, connection, folder_id=None):
        folder_id = folder_id or 'root'
        params = {
            'q': f"'{folder_id}' in parents and trashed = false",
            'orderBy': 'folder,name',
            'pageSize': 200,
            'fields': 'files(id,name,mimeType,size,modifiedTime,iconLink,thumbnailLink,webViewLink)',
            'supportsAllDrives': 'true',
            'includeItemsFromAllDrives': 'true',
        }
        r = self._api_get(connection, '/files', params=params)
        files = r.json().get('files', [])
        items = []
        for f in files:
            is_folder = f.get('mimeType') == 'application/vnd.google-apps.folder'
            export = GOOGLE_EXPORT_MAP.get(f.get('mimeType') or '')
            items.append({
                'id': f['id'],
                'name': f['name'],
                'type': 'folder' if is_folder else 'file',
                'size': int(f['size']) if f.get('size') else None,
                'mime_type': f.get('mimeType'),
                'modified': f.get('modifiedTime'),
                'icon_url': f.get('iconLink'),
                'thumbnail_url': f.get('thumbnailLink'),
                'web_view_url': f.get('webViewLink'),
                'export_ext': export[0] if export else None,
                'export_mime': export[1] if export else None,
            })
        return items

    def download_file(self, connection, file_id, export_mime=None):
        # Look up the file first so we know its name / mime.
        meta = self._api_get(connection, f'/files/{file_id}',
                             params={'fields': 'id,name,mimeType,size'}).json()
        mime = meta.get('mimeType') or 'application/octet-stream'
        filename = meta.get('name') or file_id

        if mime.startswith('application/vnd.google-apps.'):
            target = GOOGLE_EXPORT_MAP.get(mime)
            if not target:
                raise RuntimeError(f"Don't know how to export Google file type: {mime}")
            ext, export_target_mime = target
            r = self._api_get(connection, f'/files/{file_id}/export',
                              params={'mimeType': export_target_mime}, stream=True)
            content = r.content
            if '.' not in filename:
                filename = f'{filename}.{ext}'
            mime = export_target_mime
        else:
            r = self._api_get(connection, f'/files/{file_id}',
                              params={'alt': 'media'}, stream=True)
            content = r.content
        return content, filename, mime


# ── Local Path (covers NFS / pre-mounted SMB / any local directory) ────────

def _local_path_allowed_roots():
    """Allowlist of base directories Local Path connections may point inside.
    Stored in OAuthAppCredentials(provider='local_path').extra.allowed_roots."""
    creds = _storage_get_app_credentials('local_path')
    if not creds:
        return []
    roots = (creds.extra or {}).get('allowed_roots') or []
    # Normalise & dedupe.
    normalised = []
    seen = set()
    for r in roots:
        if not r:
            continue
        p = os.path.abspath(os.path.expanduser(r))
        if p in seen:
            continue
        seen.add(p)
        normalised.append(p)
    return normalised


def _local_path_resolve(root, relative):
    """Resolve `relative` under `root`, refusing any traversal outside root.
    Returns the absolute path or raises ValueError."""
    root_abs = os.path.abspath(root)
    rel_clean = (relative or '').lstrip('/').lstrip('\\')
    target = os.path.abspath(os.path.join(root_abs, rel_clean))
    if target != root_abs and not target.startswith(root_abs + os.sep):
        raise ValueError('Path traversal blocked.')
    return target


class LocalPathAdapter(StorageAdapter):
    """Browse a directory tree on the local filesystem (or any mount point).
    Useful for NFS / SMB shares already mounted at the OS level.
    Connection config: { 'root_path': '/mnt/nas' }
    Folder IDs in browse responses are paths relative to root_path."""
    provider_key = 'local_path'
    display_name = 'Local / Mounted Path'
    auth_kind = 'credentials'

    @staticmethod
    def _root_for(connection):
        root = (connection.config or {}).get('root_path')
        if not root:
            raise RuntimeError('Connection is missing root_path.')
        allowed = _local_path_allowed_roots()
        if allowed:
            root_abs = os.path.abspath(root)
            if not any(root_abs == a or root_abs.startswith(a + os.sep) for a in allowed):
                raise RuntimeError(f'root_path {root_abs!r} is no longer within the allowlist.')
        if not os.path.isdir(root):
            raise RuntimeError(f'Directory not accessible: {root}')
        return root

    def test(self, connection):
        try:
            root = self._root_for(connection)
            # Try a listdir as a real read check.
            os.listdir(root)
            return True, f"Readable: {root}"
        except Exception as e:
            return False, str(e)

    def list_folder(self, connection, folder_id=None):
        import stat as _stat
        root = self._root_for(connection)
        target = _local_path_resolve(root, folder_id or '')
        if not os.path.isdir(target):
            raise RuntimeError(f'Not a directory: {target}')
        items = []
        for name in sorted(os.listdir(target), key=str.lower):
            if name.startswith('.'):
                continue
            full = os.path.join(target, name)
            try:
                st = os.stat(full)
            except OSError:
                continue
            rel = os.path.relpath(full, root)
            is_dir = _stat.S_ISDIR(st.st_mode)
            mime = mimetypes.guess_type(name)[0] if not is_dir else None
            items.append({
                'id': rel.replace(os.sep, '/'),
                'name': name,
                'type': 'folder' if is_dir else 'file',
                'size': None if is_dir else int(st.st_size),
                'mime_type': mime,
                'modified': datetime.utcfromtimestamp(st.st_mtime).isoformat(),
            })
        # Folders first, then files; both case-insensitive sorted.
        items.sort(key=lambda x: (x['type'] != 'folder', x['name'].lower()))
        return items

    def download_file(self, connection, file_id, export_mime=None):
        root = self._root_for(connection)
        target = _local_path_resolve(root, file_id)
        if not os.path.isfile(target):
            raise RuntimeError('Not a file.')
        with open(target, 'rb') as f:
            content = f.read()
        filename = os.path.basename(target)
        mime = mimetypes.guess_type(filename)[0] or 'application/octet-stream'
        return content, filename, mime


# ── SMB (direct, via smbprotocol) ──────────────────────────────────────────

class SMBAdapter(StorageAdapter):
    """Direct SMB connection — no OS mount required.
    Connection config: {
        'server': '192.168.1.5',  # host or IP
        'share': 'media',         # share name (no slashes)
        'username': 'alice',      # encrypted
        'password': '...',        # encrypted
        'port': 445,              # optional
        'domain': 'WORKGROUP',    # optional, prefixed onto username if set
    }
    Folder IDs are paths inside the share (forward-slash separated)."""
    provider_key = 'smb'
    display_name = 'SMB / CIFS'
    auth_kind = 'credentials'

    @staticmethod
    def _smb_path(connection, relative=''):
        cfg = connection.config or {}
        server = cfg.get('server', '').strip()
        share = cfg.get('share', '').strip()
        rel = (relative or '').strip('/').replace('/', '\\')
        if not server or not share:
            raise RuntimeError('Connection missing server/share.')
        path = f'\\\\{server}\\{share}'
        if rel:
            path = f'{path}\\{rel}'
        return path

    @staticmethod
    def _register(connection):
        """Open / refresh the SMB session for this connection.
        smbclient.register_session is idempotent per (server, user)."""
        import smbclient
        cfg = connection.config or {}
        username = decrypt_api_key(cfg.get('username') or '')
        password = decrypt_api_key(cfg.get('password') or '')
        domain = (cfg.get('domain') or '').strip()
        port = int(cfg.get('port') or 445)
        full_username = f'{domain}\\{username}' if domain else username
        smbclient.register_session(
            cfg.get('server'),
            username=full_username or None,
            password=password or None,
            port=port,
        )

    def test(self, connection):
        try:
            import smbclient
            self._register(connection)
            path = self._smb_path(connection)
            # listdir on the share root proves auth + reachability
            smbclient.listdir(path)
            return True, f'Connected to {path}'
        except Exception as e:
            return False, str(e)

    def list_folder(self, connection, folder_id=None):
        import smbclient
        import stat as _stat
        self._register(connection)
        path = self._smb_path(connection, folder_id or '')
        items = []
        for name in sorted(smbclient.listdir(path), key=str.lower):
            if name.startswith('.'):
                continue
            full = path + '\\' + name
            try:
                st = smbclient.stat(full)
            except Exception:
                continue
            rel_parts = [p for p in (folder_id or '').split('/') if p] + [name]
            rel = '/'.join(rel_parts)
            is_dir = _stat.S_ISDIR(st.st_mode)
            mime = mimetypes.guess_type(name)[0] if not is_dir else None
            items.append({
                'id': rel,
                'name': name,
                'type': 'folder' if is_dir else 'file',
                'size': None if is_dir else int(st.st_size),
                'mime_type': mime,
                'modified': datetime.utcfromtimestamp(st.st_mtime).isoformat(),
            })
        items.sort(key=lambda x: (x['type'] != 'folder', x['name'].lower()))
        return items

    def download_file(self, connection, file_id, export_mime=None):
        import smbclient
        self._register(connection)
        path = self._smb_path(connection, file_id)
        with smbclient.open_file(path, mode='rb') as f:
            content = f.read()
        filename = file_id.rsplit('/', 1)[-1] if '/' in file_id else file_id
        mime = mimetypes.guess_type(filename)[0] or 'application/octet-stream'
        return content, filename, mime


# ── Adapter registry ───────────────────────────────────────────────────────

_STORAGE_ADAPTERS = {
    'google_drive': GoogleDriveAdapter(),
    'local_path':   LocalPathAdapter(),
    'smb':          SMBAdapter(),
}


def get_storage_adapter(provider):
    return _STORAGE_ADAPTERS.get(provider)


# ── Helper: import a downloaded blob into the Asset library ────────────────

def _import_blob_to_asset_library(user_id, folder_id, original_filename,
                                  content_bytes, mime_type, source_label):
    """Wrap raw bytes in a FileStorage so save_asset_file() can process it.
    Returns the created Asset or raises ValueError."""
    from werkzeug.datastructures import FileStorage
    import io as _io

    config = get_asset_library_config()
    max_single_bytes = mb_to_bytes(config.get('max_single_file_mb', 50))
    max_total_bytes = mb_to_bytes(config.get('max_total_storage_mb', 500))
    used_bytes = get_user_asset_storage_bytes(user_id)

    size = len(content_bytes)
    if size > max_single_bytes:
        raise ValueError(f'"{original_filename}" exceeds the '
                         f'{config.get("max_single_file_mb", 50)} MB single-file limit.')
    if used_bytes + size > max_total_bytes:
        raise ValueError(f'Import would exceed your storage limit '
                         f'({format_bytes(max_total_bytes - used_bytes)} remaining).')
    if not is_allowed_asset_file(original_filename):
        ext = get_asset_extension(original_filename)
        raise ValueError(f'"{original_filename}" has a file type that is not allowed: .{ext}')

    user_folder = os.path.join(uploads_folder, str(user_id), 'assets')
    os.makedirs(user_folder, exist_ok=True)

    bio = _io.BytesIO(content_bytes)
    fs = FileStorage(stream=bio, filename=original_filename, content_type=mime_type)
    saved = save_asset_file(fs, user_folder)

    asset_url = url_for('static', filename=f'uploads/{user_id}/assets/{saved["stored_filename"]}')
    thumbnail_url = None
    if saved.get('thumbnail_filename'):
        thumbnail_url = url_for('static',
                                filename=f'uploads/{user_id}/assets/{saved["thumbnail_filename"]}')

    asset = Asset(
        user_id=user_id,
        folder_id=folder_id,
        original_filename=saved['original_filename'],
        stored_filename=saved['stored_filename'],
        original_stored_filename=saved.get('original_stored_filename'),
        url=asset_url,
        thumbnail_url=thumbnail_url,
        asset_type=saved['asset_type'],
        mime_type=saved['mime_type'],
        extension=saved['extension'],
        file_size=saved['file_size'],
    )
    db.session.add(asset)
    return asset


